const QUESTIONS_CHFI_C4 = [
  { id:70701, domain:5, level:1, question:"Which tool is most commonly used to capture and interactively analyze live network packets during a forensic investigation?", options:["Wireshark, a graphical protocol analyzer that captures and dissects packets in real time","Autopsy, a disk imaging suite designed for filesystem timeline reconstruction only","FTK Imager, a utility built specifically for acquiring forensic images of hard disks in this context","Volatility, a framework focused entirely on parsing memory dump structures offline"], correct:0, explanation:"Wireshark is the standard live packet analyzer. Autopsy and FTK Imager target disk evidence, and Volatility parses memory dumps, so none capture live network traffic." },
  { id:70702, domain:5, level:1, question:"What is the native file format produced by tcpdump when writing captured traffic to disk for later analysis?", options:["A plain text CSV listing that stores only summarized connection metadata per row","A PCAP file containing raw captured frames with timestamps and full packet payloads","A JSON document that encodes decoded application-layer fields for each observed flow","An SQLite database indexing every packet by source and destination address pairs"], correct:1, explanation:"tcpdump writes libpcap (PCAP) files with raw frames and timestamps. It does not natively emit CSV, JSON, or SQLite; those require separate conversion tooling." },
  { id:70703, domain:5, level:2, question:"During analysis of a PCAP, which Wireshark display filter isolates only traffic to or from the host 10.0.0.5?", options:["tcp.port eq 10.0.0.5 which restricts the view strictly to that numeric TCP port value","http.host contains 10.0.0.5 which matches the HTTP host header field for that string","ip.addr == 10.0.0.5 which matches packets where either address field equals that host","frame.len > 10 which shows only frames whose captured length exceeds ten bytes total"], correct:2, explanation:"ip.addr == matches source or destination IP. tcp.port expects a port not an IP, http.host filters HTTP headers only, and frame.len filters by size, not host." },
  { id:70704, domain:5, level:2, question:"Which flow-export technology, developed by Cisco, records summary metadata about IP conversations rather than full packet payloads?", options:["SNMP, which polls device counters to report interface utilization and error metrics in this context","Syslog, which forwards textual event messages generated by network device daemons","RADIUS, which centralizes authentication and accounting for remote access sessions","NetFlow, which exports records describing source, destination, ports, and byte counts"], correct:3, explanation:"NetFlow exports conversation metadata (5-tuple, bytes, packets). SNMP polls counters, Syslog carries text events, and RADIUS handles auth/accounting, not flow records." },
  { id:70705, domain:5, level:2, question:"An investigator sees many ARP replies mapping the gateway IP to different MAC addresses in seconds. What attack is indicated?", options:["An ARP spoofing attack in which an attacker forges replies to redirect LAN traffic","A DNS cache poisoning attack that forges resolver responses to redirect name lookups","A SYN flood attack that exhausts server connection tables with half-open TCP sessions","A brute-force attack that repeatedly guesses credentials against an exposed service"], correct:0, explanation:"Rapidly changing IP-to-MAC bindings signal ARP spoofing. DNS poisoning targets name resolution, SYN floods target TCP state, and brute force targets logins, not ARP tables." },
  { id:70706, domain:5, level:3, question:"In IPFIX, which concept lets a collector interpret the structure and meaning of the data records an exporter sends?", options:["A sampling rate value that specifies the fraction of packets selected for observation","A template record that defines the fields, types, and ordering of subsequent data records","A sequence number that solely detects lost export packets between exporter and collector in this context","An observation domain identifier that only groups metering processes on one device"], correct:1, explanation:"IPFIX template records define field layout so collectors can parse data records. Sampling rate, sequence numbers, and observation domains serve other functions, not field definition." },
  { id:70707, domain:5, level:1, question:"Which network device log is the primary source for determining whether a connection was permitted or denied at the perimeter?", options:["The DHCP server lease log that records which addresses were assigned to which clients in this context","The NTP server log that documents time synchronization requests from internal hosts","The firewall log that records allowed and denied connections with associated rule actions","The print server log that captures document spooling jobs submitted by workstations"], correct:2, explanation:"Firewall logs record allow/deny decisions per rule. DHCP logs track leases, NTP logs track time sync, and print logs track spooling, none of which show perimeter filtering." },
  { id:70708, domain:5, level:2, question:"A proxy server access log shows repeated GET requests to a single external URL every 60 seconds from one host. What does this most likely indicate?", options:["Normal software update polling that always uses randomized long intervals between checks","A misconfigured NTP client repeatedly attempting to synchronize the workstation clock","An email client downloading new messages using the standard IMAP idle notification","Malware beaconing to a command-and-control server using regular timed callback requests"], correct:3, explanation:"Fixed-interval repeated callbacks are classic C2 beaconing. Update polling is irregular, NTP uses UDP/123 not HTTP GET, and IMAP idle does not repeat GETs to a URL." },
  { id:70709, domain:5, level:3, question:"When reconstructing a data exfiltration event, which observation in DNS logs most strongly suggests DNS tunneling was used?", options:["Unusually long, high-entropy subdomain labels queried in large volume to one nameserver","A small number of A record lookups for well-known public web domains during business hours","Periodic reverse PTR lookups mapping internal addresses to their assigned hostnames","Occasional NXDOMAIN responses returned for common typo variants of legitimate sites"], correct:0, explanation:"DNS tunneling encodes data in long high-entropy subdomains sent in volume to one authoritative server. Normal A lookups, PTR queries, and stray NXDOMAINs are benign patterns." },
  { id:70710, domain:5, level:2, question:"Which characteristic in a packet capture is the clearest signal of a TCP SYN scan against a host?", options:["A single long-lived TCP session transferring a large file with normal window scaling","Many SYN packets sent to sequential ports with RST or no response returning for each","Repeated full three-way handshakes followed by legitimate application data exchange","A steady stream of UDP datagrams to port 53 carrying valid DNS query structures"], correct:1, explanation:"SYN scans send SYNs across many ports expecting RST or silence, never completing handshakes. Full handshakes with data and normal DNS traffic are legitimate, not scans." },
  { id:70711, domain:5, level:1, question:"In 802.11 wireless forensics, what is a rogue access point?", options:["A vendor-certified access point that has been correctly registered in the asset inventory","A guest access point intentionally isolated on a separate VLAN for visitor internet use","An unauthorized access point connected to the network without administrative approval","A backup access point kept powered off and stored for disaster recovery replacement"], correct:2, explanation:"A rogue AP is an unauthorized device attached to the network. Certified inventoried APs, sanctioned guest APs, and offline spares are all authorized or inactive, not rogue." },
  { id:70712, domain:5, level:2, question:"An evil twin attack against a wireless network is best described by which of the following?", options:["An attacker duplicates a MAC address to bypass a wired switch port security setting","An attacker floods the channel with deauthentication frames to disrupt all clients","An attacker cracks a WPA2 pre-shared key offline using a captured handshake file","An attacker stands up a fake AP with the same SSID to lure clients into connecting"], correct:3, explanation:"An evil twin mimics a legitimate SSID to capture client connections. MAC spoofing targets switch ports, deauth floods cause DoS, and PSK cracking is a separate offline attack." },
  { id:70713, domain:5, level:3, question:"To later crack a WPA2-PSK network offline, which specific exchange must a forensic examiner capture from the air?", options:["The full four-way handshake between the client and access point during association","The complete DHCP DISCOVER and OFFER exchange occurring after the client joins in this context","The beacon frames broadcast by the access point advertising its SSID and rates","The ARP request and reply pair the client issues to locate the default gateway"], correct:0, explanation:"WPA2-PSK offline cracking needs the four-way handshake, which carries the key-derivation nonces. DHCP, beacons, and ARP exchanges contain no material for PSK recovery." },
  { id:70714, domain:5, level:2, question:"Which entry in an Apache access log field set records the URL or resource the client requested?", options:["The remote host field, which stores the client IP address that originated the request in this context","The request line field, which stores the method, requested resource path, and protocol","The user-agent field, which stores the browser and platform string sent by the client","The status code field, which stores the numeric HTTP result returned for the request"], correct:1, explanation:"The request line holds the method, path, and protocol. The remote host is the client IP, user-agent is the client string, and the status code is the numeric response result." },
  { id:70715, domain:5, level:2, question:"A web server log shows a request containing ' OR '1'='1 in a query string parameter. What attack does this indicate?", options:["A cross-site scripting attempt that injects script into a page rendered for other users","A directory traversal attempt that uses dot-dot sequences to escape the web root","A SQL injection attempt that manipulates a backend query using a boolean tautology","A server-side request forgery attempt that coerces the server to fetch internal URLs"], correct:2, explanation:"' OR '1'='1 is a classic SQL injection tautology. XSS injects script tags, traversal uses ../ sequences, and SSRF supplies internal URLs, none of which match this payload." },
  { id:70716, domain:5, level:3, question:"Which artifact left on a web server most directly indicates that a web shell has been deployed by an attacker?", options:["An entry in the standard access log recording a normal GET request for the homepage","A rotated log archive compressed with gzip according to the routine retention policy in this context","A cached static image stored by the server to accelerate repeated content delivery","A suspicious script file in a writable web directory that accepts commands via parameters"], correct:3, explanation:"A web shell is an attacker-planted script accepting commands over HTTP. Normal homepage GETs, routine log rotation, and cached images are all expected, benign server artifacts." },
  { id:70717, domain:5, level:1, question:"In cloud forensics, the shared responsibility model primarily clarifies which of the following?", options:["The division of security and evidence duties between the cloud provider and customer","The billing split that determines how monthly usage charges are allocated to teams in this context","The order in which cloud regions fail over when an availability zone loses power","The schedule the provider follows when applying patches to customer applications"], correct:0, explanation:"Shared responsibility defines which security duties belong to provider versus customer. It is not about billing splits, failover ordering, or patching customer-owned applications." },
  { id:70718, domain:5, level:2, question:"Which AWS service is the authoritative source of API activity records showing who performed which management actions and when?", options:["Amazon CloudWatch, which primarily collects operational metrics and application log streams in this context","AWS CloudTrail, which records API calls including identity, action, time, and source address","Amazon S3, which provides scalable object storage for files, backups, and static content","AWS IAM, which defines users, roles, and the policies that grant permissions to them"], correct:1, explanation:"CloudTrail logs API calls with identity and time. CloudWatch handles metrics/logs, S3 stores objects, and IAM manages permissions but does not itself record the API call history." },
  { id:70719, domain:5, level:2, question:"To forensically acquire the disk of a running AWS EC2 instance without shutting it down, which approach is preferred?", options:["Delete the instance immediately so the underlying storage is preserved by the provider in this context","Reboot the instance into single-user mode and image the disk with a live USB toolkit","Create an EBS snapshot of the attached volume and mount a copy to an investigation host","Ask the tenant to email a zipped copy of important files from inside the instance"], correct:2, explanation:"An EBS snapshot captures the volume state for isolated analysis. Deleting destroys evidence, rebooting alters state and may not be possible, and emailing files is not forensically sound." },
  { id:70720, domain:5, level:3, question:"Which challenge is most unique to cloud forensics compared with traditional on-premises disk forensics?", options:["Write blockers cannot be attached to spinning disks during the imaging acquisition step in this context","Hash values computed with SHA-256 cannot be verified once the image has been created","Chain-of-custody forms are never required for evidence collected in enterprise settings","Multi-tenancy and cross-jurisdiction data storage complicate access, isolation, and legal authority"], correct:3, explanation:"Multi-tenancy and jurisdiction issues are distinctive cloud problems. Write blockers apply to physical disks, hashing still verifies images, and chain of custody is always required." },
  { id:70721, domain:5, level:1, question:"Which Azure service provides subscription-level records of control-plane operations such as resource creation and deletion?", options:["Azure Activity Log, which records subscription control-plane events and their initiators","Azure Blob Storage, which stores unstructured object data for applications and backups","Azure DevOps, which manages source code repositories and continuous delivery pipelines","Azure Active Directory, which handles identity, sign-in, and directory group management in this context"], correct:0, explanation:"The Azure Activity Log records control-plane operations and who initiated them. Blob Storage stores data, DevOps manages code, and Azure AD handles identity, not resource operations." },
  { id:70722, domain:5, level:2, question:"In Google Cloud Platform, which log category records administrative actions that modify resource configuration or metadata?", options:["Data Access audit logs, which by default record only reads of user-supplied resource data","Admin Activity audit logs, which record configuration changes and are enabled by default","VPC Flow Logs, which record only network connection metadata between compute instances","Error Reporting logs, which aggregate application stack traces from running workloads"], correct:1, explanation:"Admin Activity audit logs capture config-changing actions and are always on. Data Access logs cover reads, VPC Flow Logs cover network flows, and Error Reporting covers app errors." },
  { id:70723, domain:5, level:2, question:"A SIEM correlation rule fires when a single account logs in from two distant countries within minutes. What is this pattern called?", options:["A pass-the-hash detection that identifies reuse of stolen NTLM authentication material","A privilege escalation alert triggered when a standard user is added to an admin group","An impossible travel alert indicating logins from locations too far apart in the time span","A data loss prevention hit triggered when sensitive file content leaves the organization in this context"], correct:2, explanation:"Geographically impossible logins in a short window define impossible travel. Pass-the-hash, privilege escalation, and DLP hits describe different detection scenarios entirely." },
  { id:70724, domain:5, level:3, question:"When investigating a suspected DDoS, which combination of evidence best distinguishes a volumetric flood from a legitimate traffic spike?", options:["A gradual rise in unique customers with valid sessions completing normal checkout flows in this context","A scheduled marketing email causing a brief predictable increase in homepage page views","A backup job saturating internal bandwidth between two known servers overnight nightly","A sudden surge of traffic from many spoofed sources with malformed or repetitive requests"], correct:3, explanation:"Volumetric DDoS shows sudden surges from many spoofed sources with abnormal requests. Real customer growth, marketing spikes, and internal backups are legitimate, explainable traffic." },
  { id:70725, domain:5, level:2, question:"Which field in an email header is most useful for tracing the path a message traveled between mail servers?", options:["The Received headers, which each mail server prepends as the message is relayed onward","The Subject field, which contains the human-readable topic chosen by the sender","The To field, which lists the intended recipient addresses supplied by the sender","The X-Priority field, which indicates the importance flag set by the sending client in this context"], correct:0, explanation:"Received headers are added by each relay, forming a traceable path. Subject, To, and X-Priority are sender-controlled and reveal nothing about the servers that handled the message." },
  { id:70726, domain:5, level:1, question:"What does a NIDS (network intrusion detection system) primarily do?", options:["It blocks malicious files from being written to disk on individual endpoint devices in this context","It monitors network traffic and generates alerts when it detects suspicious patterns","It encrypts data in transit between two hosts using a negotiated symmetric key","It assigns IP addresses to clients as they join and leave the local network segment"], correct:1, explanation:"A NIDS inspects traffic and alerts on suspicious patterns. Endpoint file blocking is host antivirus, encryption is a VPN/TLS role, and address assignment is DHCP's function." },
  { id:70727, domain:5, level:2, question:"Which statement best distinguishes an IPS from an IDS in network forensics context?", options:["An IDS operates only on encrypted traffic, while an IPS is limited to plaintext protocols in this context","An IPS stores full packet captures forever, while an IDS never retains any packet data","An IPS can actively block or drop malicious traffic inline, while an IDS only alerts on it","An IDS requires a hardware TAP, while an IPS can only run as a cloud-hosted service"], correct:2, explanation:"An IPS sits inline and can block; an IDS passively alerts. Both handle traffic regardless of encryption, retention is configurable, and deployment options are not that rigid." },
  { id:70728, domain:5, level:3, question:"An analyst reconstructs a session and finds an HTTP POST carrying a large base64 blob to an unfamiliar external host. What is the strongest interpretation?", options:["A routine software telemetry ping that always transmits only a few bytes of status","A standard TLS handshake exchanging certificates before an encrypted channel begins","A DNS zone transfer replicating authoritative records to a secondary nameserver host in this context","Possible data exfiltration in which encoded stolen content is uploaded to an attacker host"], correct:3, explanation:"A large base64 upload to an unknown host suggests exfiltration. Telemetry pings are small, TLS handshakes are not HTTP POST bodies, and zone transfers use DNS, not HTTP." },
  { id:70729, domain:5, level:2, question:"In a router log, which detail is most valuable for correlating an internal host to external activity behind NAT?", options:["The NAT translation table entries mapping internal IP and port to external IP and port","The router firmware version string, which identifies the software build currently loaded","The device hostname, which is a human-assigned label for the router in the inventory","The configured MOTD banner text, which is displayed to administrators upon login access"], correct:0, explanation:"NAT translation entries link internal to external address/port pairs, enabling attribution. Firmware version, hostname, and login banners provide no mapping for tracing sessions." },
  { id:70730, domain:5, level:1, question:"Which protocol analyzer command-line tool is commonly used on servers to capture traffic where no GUI is available?", options:["Photoshop, a raster graphics editor used to manipulate and composite digital images","tcpdump, a command-line packet capture and filtering tool built on the libpcap library","Nmap, a scanner used to enumerate open ports and fingerprint services on remote hosts","Metasploit, an exploitation framework used to develop and launch attack payloads at targets"], correct:1, explanation:"tcpdump is the CLI capture tool for headless servers. Photoshop edits images, Nmap scans ports rather than captures traffic, and Metasploit is an exploitation framework." },
  { id:70731, domain:5, level:2, question:"Which S3 feature must be enabled to record who accessed which objects in an AWS bucket for forensic review?", options:["Bucket versioning, which retains prior copies of objects but not any request-level access data","Cross-region replication, which copies objects to another region for durability and recovery","Server access logging or CloudTrail data events, which record object-level request details","Lifecycle policies, which transition or expire objects based on configured age thresholds"], correct:2, explanation:"S3 server access logs or CloudTrail data events capture object-level access. Versioning keeps copies, replication copies data, and lifecycle rules manage storage tiers, not access records." },
  { id:70732, domain:5, level:3, question:"During container forensics, why is capturing the running container's memory and filesystem promptly especially important?", options:["Containers use write-once media that can never be altered after the initial image build","Containers store all evidence permanently in the host BIOS regardless of their lifecycle in this context","Containers cannot be imaged at all, so only external network logs are ever available","Containers are often ephemeral and their state can vanish when they stop or are rescheduled"], correct:3, explanation:"Ephemeral containers lose state on stop or reschedule, so prompt capture matters. They do not use write-once media, do not store evidence in BIOS, and can be imaged." },
  { id:70733, domain:5, level:2, question:"Which Wireshark feature reassembles the full application-layer conversation from a set of related TCP packets?", options:["The Follow TCP Stream option, which reconstructs and displays the bidirectional payload data","The IO Graph view, which plots packet counts and throughput against elapsed capture time","The Expert Information panel, which summarizes warnings, errors, and notable protocol events","The Time Reference marker, which resets the displayed timestamp offset for later packets"], correct:0, explanation:"Follow TCP Stream reassembles a conversation's payload. IO Graph plots rates, Expert Info flags anomalies, and Time Reference adjusts timestamps, none reconstructing the stream." },
  { id:70734, domain:5, level:2, question:"A DHCP server log is most useful in an investigation for establishing which of the following facts?", options:["The exact bytes of application data a client transmitted to an external web server host","Which MAC address held a given IP address at a specific time via the lease assignment","The cryptographic keys negotiated during a TLS session between two internal endpoints","The precise CPU and memory utilization of the workstation during the incident window"], correct:1, explanation:"DHCP lease logs tie a MAC to an IP over a time window, aiding attribution. They contain no payload data, no TLS keys, and no host resource-utilization metrics." },
  { id:70735, domain:5, level:1, question:"What is the primary purpose of a network TAP in forensic monitoring?", options:["To translate private internal IP addresses into routable public addresses at the edge","To assign quality-of-service priorities to voice packets crossing a congested link","To passively copy traffic from a link so a monitor can observe it without disruption","To terminate VPN tunnels and decrypt their contents for internal application servers"], correct:2, explanation:"A TAP passively mirrors link traffic for monitoring without interfering. NAT translates addresses, QoS prioritizes packets, and VPN concentrators terminate tunnels, unlike a TAP." },
  { id:70736, domain:5, level:3, question:"When correlating events across a firewall, IDS, and web server, why is consistent time synchronization critical?", options:["It ensures all logs occupy exactly the same amount of disk storage on each device","It guarantees that every log entry is automatically encrypted at rest by each device in this context","It prevents attackers from ever connecting to any of the monitored network services","It lets an investigator align events into an accurate timeline of the attack sequence"], correct:3, explanation:"Synchronized clocks let events be ordered into a coherent timeline across sources. Time sync does not affect storage size, encryption, or an attacker's ability to connect." },
  { id:70737, domain:5, level:2, question:"Which observation in NetFlow data best supports a hypothesis of internal reconnaissance by a compromised host?", options:["One host opening short connections to many internal hosts across many ports quickly","Two hosts exchanging a single large sustained transfer over one well-known service port","A host receiving inbound web traffic from thousands of distinct external client addresses","A host synchronizing its clock with an internal NTP server at regular short intervals"], correct:0, explanation:"Many short connections fanning out to many hosts and ports indicate scanning. A single large transfer, inbound web serving, and NTP sync are normal, non-recon patterns." },
  { id:70738, domain:5, level:2, question:"In cloud environments, which evidence type is typically most accessible to investigators for a SaaS application breach?", options:["Physical disk images of the underlying servers hosting the multi-tenant SaaS platform","Provider-exposed application and admin audit logs recording user actions and access events","Raw hypervisor memory dumps from the specific host where the tenant workload ran","Firmware images from the storage controllers backing the provider's shared storage array in this context"], correct:1, explanation:"For SaaS, customers typically get audit logs of user actions, not infrastructure. Physical images, hypervisor memory, and controller firmware are provider-controlled and rarely accessible." },
  { id:70739, domain:5, level:3, question:"Which analysis of TLS-encrypted traffic can still yield forensic value without decrypting the payload?", options:["Reading the plaintext HTTP request bodies contained inside the encrypted TLS records in this context","Recovering the exact passwords a user typed into the encrypted login form submission","Examining metadata like SNI, certificate details, JA3 fingerprints, timing, and volumes","Extracting the full email message text transmitted over the secured SMTP connection"], correct:2, explanation:"Even without decryption, SNI, certificates, JA3, timing, and volume reveal much. Request bodies, typed passwords, and message text remain protected inside the encrypted channel." },
  { id:70740, domain:5, level:1, question:"Which log records DNS query and response activity useful for tracing malware domain lookups?", options:["The SMTP relay log, which records message envelopes and delivery attempts between servers","The RADIUS accounting log, which records session start and stop events for remote users","The NTP peer log, which records clock offset adjustments negotiated with time sources","The DNS server or resolver log, which records queried names and the responses returned"], correct:3, explanation:"DNS resolver logs capture queried names and answers, exposing malicious lookups. SMTP, RADIUS, and NTP logs record mail, authentication, and time events respectively." },
  { id:70741, domain:5, level:2, question:"A packet capture reveals a client and server exchanging traffic on TCP port 4444 with shell-like command output. What is the most likely explanation?", options:["A reverse shell connection, as port 4444 is frequently used by exploitation frameworks","A legitimate HTTPS session, since browsers commonly negotiate secure pages on port 4444","A standard DNS resolution exchange that carries query and answer records on port 4444","A routine NTP synchronization request that clients send to time servers using port 4444"], correct:0, explanation:"Port 4444 with interactive command output is a common reverse shell, often from Metasploit. HTTPS uses 443, DNS uses 53, and NTP uses 123, none of which match this behavior." },
  { id:70742, domain:5, level:2, question:"Which artifact best helps determine whether a firewall rule change enabled an intrusion?", options:["The workstation's browser history listing the websites a user visited during the same period","The firewall configuration change log or audit trail showing who altered which rule and when","The mail server quarantine folder containing spam messages filtered from user inboxes","The printer accounting record listing pages printed by each department over the month"], correct:1, explanation:"A firewall config change audit trail shows rule modifications and who made them. Browser history, mail quarantine, and print accounting are unrelated to firewall rule changes." },
  { id:70743, domain:5, level:3, question:"When acquiring evidence from an IaaS virtual machine, which method preserves the most complete forensic state?", options:["Copying only a handful of suspicious files the tenant identifies from inside the guest","Recording only the provider billing statement showing the hours the instance ran","Capturing both a disk snapshot and a volatile memory dump of the running instance","Screenshotting the cloud console dashboard displaying the instance's status summary"], correct:2, explanation:"Disk snapshot plus memory dump captures persistent and volatile state. Selective file copies, billing statements, and console screenshots miss the bulk of forensic evidence." },
  { id:70744, domain:5, level:2, question:"Which indicator in web server logs most strongly suggests automated scanning rather than human browsing?", options:["A user visiting three related product pages over several minutes with normal referrers","A logged-in customer completing a checkout after adding several items to the cart","A returning visitor loading cached images with conditional requests over a long session","Thousands of requests per minute enumerating many nonexistent paths from one address"], correct:3, explanation:"High-rate enumeration of many nonexistent paths from one source indicates automated scanning. Deliberate browsing, checkouts, and cached revisits reflect ordinary human behavior." },
  { id:70745, domain:5, level:1, question:"What is a MITM (man-in-the-middle) attack in a network forensic context?", options:["An attack in which an attacker secretly relays and possibly alters traffic between two parties","An attack that overwhelms a server with more requests than it can possibly process","An attack that guesses a password by systematically trying every possible combination","An attack that encrypts a victim's files and demands payment to restore access to them in this context"], correct:0, explanation:"MITM intercepts and possibly modifies traffic between two parties. Overwhelming a server is DoS, systematic guessing is brute force, and file encryption for payment is ransomware." },
  { id:70746, domain:5, level:2, question:"Which Wireshark statistic quickly identifies the pair of hosts exchanging the most data in a capture?", options:["The Protocol Hierarchy window, which breaks down captured bytes by protocol layer only","The Conversations window, which lists endpoint pairs ranked by packets and bytes exchanged","The Capture File Properties dialog, which reports overall duration and total frame counts in this context","The Coloring Rules editor, which assigns display colors to packets matching set filters"], correct:1, explanation:"The Conversations window ranks endpoint pairs by traffic volume. Protocol Hierarchy breaks down by protocol, File Properties shows totals, and Coloring Rules only affect display." },
  { id:70747, domain:5, level:3, question:"Why is cross-jurisdictional data location a serious concern when collecting cloud evidence?", options:["Because cloud data is always stored unencrypted regardless of the provider's configuration","Because encryption keys are automatically shared with every jurisdiction that requests them in this context","Because differing national laws may govern access, and legal authority may not extend abroad","Because cloud providers are legally required to delete all evidence after ninety days pass"], correct:2, explanation:"Data in another country may fall under different laws, limiting an investigator's authority. Cloud data is often encrypted, keys are not auto-shared, and no universal deletion rule exists." },
  { id:70748, domain:5, level:2, question:"A proxy log entry shows an HTTP CONNECT request to an unfamiliar host on port 443 followed by a long opaque session. What should the investigator consider?", options:["It is definitely benign because port 443 traffic is always ordinary web browsing activity in this context","It is certainly a DNS query since CONNECT is the method used to resolve hostnames","It confirms a printer sending a job because CONNECT is the standard print spooling verb","It may be a tunneled or encrypted channel worth correlating with threat intelligence sources"], correct:3, explanation:"A CONNECT tunnel to an unknown host warrants correlation with threat intel. Port 443 is not automatically benign, CONNECT is not a DNS or print operation but an HTTP tunnel setup." },
  { id:70749, domain:5, level:2, question:"Which piece of information does a WHOIS lookup provide during network attack attribution?", options:["Registration and ownership details for a domain or IP block, including registrar contacts","The full packet payload of every connection made to the domain during the incident","The live CPU and memory utilization of the server currently hosting the target website in this context","The complete list of employees who work at the organization that owns the domain name"], correct:0, explanation:"WHOIS returns registration/ownership data for domains and IP ranges. It does not reveal packet payloads, live server metrics, or staff rosters of the owning organization." },
  { id:70750, domain:5, level:1, question:"Which term describes the deliberate placement of sensors to record traffic at strategic network locations?", options:["Network segmentation, which divides a network into isolated zones to limit lateral movement","Sensor or capture point placement, positioning monitors where relevant traffic can be observed","Port address translation, which rewrites source ports so many hosts share one public address in this context","Load balancing, which distributes incoming client requests across a pool of backend servers"], correct:1, explanation:"Placing capture points positions monitors to observe relevant traffic. Segmentation isolates zones, PAT rewrites ports, and load balancing spreads requests, none about sensor placement." },
  { id:70751, domain:5, level:3, question:"An investigator finds beaconing that varies its callback interval slightly around a mean. What technique is the malware most likely using?", options:["Fast flux, which rapidly rotates the DNS A records mapped to a single malicious domain","Domain generation, which algorithmically produces many candidate rendezvous domain names in this context","Jitter, which randomizes beacon timing to evade simple fixed-interval detection heuristics","Port knocking, which sends a sequence of connection attempts to open a firewall port"], correct:2, explanation:"Adding random variance around a mean interval is jitter, meant to defeat fixed-interval detection. Fast flux rotates IPs, DGA generates domains, and port knocking opens ports." },
  { id:70752, domain:5, level:2, question:"Which log source is most authoritative for confirming that a specific user authenticated to a VPN at a given time?", options:["The DHCP scope log recording which addresses were leased to which client MAC addresses","The web proxy cache directory listing objects the user retrieved during the browsing session in this context","The switch MAC address table showing which port each connected device was learned on","The VPN or RADIUS authentication and accounting log recording session start with the username"], correct:3, explanation:"VPN/RADIUS auth logs record the authenticated username and session times. DHCP leases, proxy caches, and MAC tables show addressing or content, not VPN authentication events." },
  { id:70753, domain:5, level:2, question:"In an Nginx access log, which value is recorded to indicate how the server responded to each request?", options:["The HTTP status code such as 200, 404, or 500 that reports the outcome of the request","The upstream DNS server address that Nginx queried to resolve the client's hostname","The TLS session ticket lifetime negotiated between the client and the Nginx listener","The kernel scheduling priority assigned to the worker process handling the connection"], correct:0, explanation:"Nginx logs the HTTP status code per request. It does not log the upstream DNS resolver, the TLS ticket lifetime, or the worker's kernel scheduling priority in the access log." },
  { id:70754, domain:5, level:3, question:"When a VM is suspected of compromise, why might acquiring evidence at the hypervisor level be advantageous?", options:["The hypervisor automatically decrypts all guest disk encryption without needing any keys","The hypervisor can capture VM disk and memory state externally, harder for guest malware to tamper with","The hypervisor stores a permanent unchangeable copy of every keystroke typed in the guest in this context","The hypervisor prevents the guest operating system from ever writing to its virtual disk"], correct:1, explanation:"Hypervisor-level capture obtains VM state externally, resisting in-guest tampering. It does not magically decrypt guest volumes, log keystrokes, or block guest disk writes." },
  { id:70755, domain:5, level:2, question:"Which characteristic distinguishes a stored XSS trace in web logs from a reflected XSS attempt?", options:["Stored XSS payloads only ever appear in encrypted TLS traffic and never reach the server logs","Reflected XSS requires the attacker to have valid administrator credentials on the web server","Stored XSS payload submission is logged once at injection, then served to many later victims","Reflected XSS always modifies the server's database while stored XSS never touches storage"], correct:2, explanation:"Stored XSS is injected once then repeatedly served, while reflected XSS appears in the crafted request itself. XSS traces do reach logs, need no admin creds, and reflected XSS does not write to storage." },
  { id:70756, domain:5, level:1, question:"What does the acronym SIEM stand for in security operations?", options:["Secure Internet Encryption Method, a standard for protecting web traffic between hosts","System Integrity Enforcement Module, a kernel component preventing unauthorized code changes","Signal Interference Elimination Mechanism, a wireless feature that reduces channel noise","Security Information and Event Management, a platform aggregating and correlating log data"], correct:3, explanation:"SIEM means Security Information and Event Management, aggregating and correlating logs. The other expansions are invented and do not describe the log-analysis platform." },
  { id:70757, domain:5, level:2, question:"Which factor most limits the completeness of a packet capture taken at a single switch port?", options:["Without port mirroring, a switch forwards unicast frames only to the destination port","The capture will include decrypted contents of every TLS session on the entire network","The capture always contains traffic from every VLAN configured anywhere in the building","Packet captures on switches automatically strip all source and destination IP addresses"], correct:0, explanation:"Switches forward unicast only to the target port, so without mirroring a capture misses most traffic. Captures do not auto-decrypt TLS, span all VLANs, or strip IP addresses." },
  { id:70758, domain:5, level:3, question:"An analyst must prove a file was exfiltrated over FTP. Which combination of evidence is strongest?", options:["Only the destination server's public marketing page describing its file-hosting features","The PCAP showing the STOR command and file bytes plus firewall logs of the outbound session","A single screenshot of the suspect's desktop wallpaper taken during the investigation","The suspect's verbal statement alone, with no supporting network or host artifacts recorded"], correct:1, explanation:"A PCAP of the FTP STOR with payload plus corroborating firewall logs directly proves transfer. A marketing page, a wallpaper screenshot, or an uncorroborated statement prove little." },
  { id:70759, domain:5, level:2, question:"Which cloud log would most directly reveal that an attacker created new IAM credentials in AWS?", options:["An S3 server access log entry recording a GET request for a publicly readable static object in this context","A CloudWatch metric datapoint reporting elevated CPU utilization on a compute instance","A CloudTrail event recording the CreateAccessKey or CreateUser API call and its caller identity","A VPC Flow Log record showing an accepted TCP connection between two private subnets"], correct:2, explanation:"CloudTrail logs IAM API calls like CreateAccessKey with caller identity. S3 access logs show object reads, CloudWatch shows metrics, and VPC Flow Logs show network flows, not IAM changes." },
  { id:70760, domain:5, level:2, question:"Which behavior in DHCP logs could indicate a rogue DHCP server on the network?", options:["Clients receiving consistent leases from the single authorized server within its scope range","The authorized server renewing existing leases for known clients at the halfway lease interval","The authorized server logging routine DHCP DISCOVER messages from newly connected clients","Clients receiving conflicting configuration or leases from an unexpected unauthorized server"], correct:3, explanation:"Conflicting leases from an unexpected server signals a rogue DHCP server. Consistent leases, normal renewals, and routine DISCOVER logging all reflect the sanctioned server working correctly." },
  { id:70761, domain:5, level:1, question:"Which of the following is volatile network evidence that should be collected quickly?", options:["The current ARP cache and active connection table on a running host under investigation","An archived firewall configuration file stored on a backup server for months at a time","A printed hard copy of the network diagram kept in the operations team's filing cabinet","A vendor's published datasheet describing the router model's supported feature set"], correct:0, explanation:"ARP caches and active connections are volatile and vanish on reboot, needing prompt capture. Archived configs, printed diagrams, and datasheets are static, non-volatile references." },
  { id:70762, domain:5, level:3, question:"To reconstruct an attacker's lateral movement across several internal hosts, which correlation approach is most effective?", options:["Reviewing only the marketing department's shared calendar for scheduled meeting entries in this context","Correlating authentication logs, NetFlow, and endpoint logs across hosts along a common timeline","Examining a single host's browser cache in isolation without reference to other systems","Reading the physical building's door-badge logs to see who entered the server room area"], correct:1, explanation:"Correlating auth logs, flows, and endpoint data across a timeline traces lateral movement. A single host's cache, calendars, or badge logs cannot reconstruct network-wide movement." },
  { id:70763, domain:5, level:2, question:"Which detail in an IDS alert is most important for validating whether it is a true positive?", options:["The vendor marketing name assigned to the IDS appliance model that generated the alert","The color the management console uses to display high-severity alerts in its dashboard","The packet capture or payload context associated with the alert for manual verification","The number of unrelated informational alerts the sensor generated earlier in the same day"], correct:2, explanation:"The associated packet payload lets an analyst confirm a true positive. The appliance model name, console colors, and unrelated alert counts do not help validate the specific alert." },
  { id:70764, domain:5, level:2, question:"In wireless forensics, which frame type does an attacker forge during a deauthentication attack?", options:["A data frame carrying the encrypted application payload between the client and the network in this context","A control RTS frame used to reserve the medium before a large data transmission begins","A beacon frame periodically advertising the network SSID and supported data rate set","A management deauthentication frame that forces a client to disconnect from its access point"], correct:3, explanation:"Deauth attacks forge management deauthentication frames to disconnect clients. Data frames carry payload, RTS frames reserve the medium, and beacons advertise the network." },
  { id:70765, domain:5, level:3, question:"An investigator observes a host resolving many algorithmically random-looking domains, most returning NXDOMAIN. What does this indicate?", options:["Malware using a domain generation algorithm to locate its command-and-control server","Normal web browsing, since users frequently mistype domain names during ordinary sessions","A misconfigured NTP client repeatedly failing to reach the configured time synchronization pool","A standard reverse DNS lookup process mapping internal addresses back to their hostnames"], correct:0, explanation:"Many random domains with mostly NXDOMAIN responses indicate DGA-based C2 discovery. Typos are few, NTP does not resolve random domains, and reverse lookups use structured PTR queries." },
  { id:70766, domain:5, level:2, question:"Which of the following best describes the evidentiary role of full packet capture versus flow data?", options:["Flow data preserves complete payloads while full capture only stores connection summaries","Full packet capture preserves payloads and detail, while flow data offers scalable metadata","Both store identical information, so the choice between them makes no practical difference in this context","Neither can be used as evidence because network data is inadmissible in any proceeding"], correct:1, explanation:"Full capture keeps payloads; flow data is compact metadata that scales. The two differ substantially, are not identical, and both can serve as evidence when properly handled." },
  { id:70767, domain:5, level:1, question:"What does CloudWatch primarily provide in the AWS ecosystem?", options:["A managed relational database service that stores structured transactional application data in this context","A content delivery network that caches static assets at edge locations near end users","A monitoring service collecting metrics, logs, and alarms about AWS resources and applications","An identity provider that federates single sign-on across third-party SaaS applications"], correct:2, explanation:"CloudWatch monitors metrics, logs, and alarms for AWS resources. RDS is the database service, CloudFront is the CDN, and IAM/SSO handles identity federation, not monitoring." },
  { id:70768, domain:5, level:2, question:"Which network artifact best links a specific external download to an internal workstation through a proxy?", options:["The NTP server's log of clock synchronization offsets negotiated with upstream time sources","The SMTP server's queue listing outbound messages awaiting delivery to remote domains","The switch's spanning-tree topology showing which port is the current root bridge path","The proxy access log entry recording the client IP, requested URL, timestamp, and bytes"], correct:3, explanation:"Proxy access logs tie client IP, URL, time, and size together for the download. NTP offsets, SMTP queues, and spanning-tree topology reveal nothing about the specific web download." },
  { id:70769, domain:5, level:3, question:"When investigating a compromised Kubernetes environment, which evidence source best reveals unauthorized API actions?", options:["The Kubernetes audit log recording API server requests, users, verbs, and affected resources","The container image registry's list of available base images pulled during normal builds","The node's fan speed telemetry reported by the underlying hardware management controller","The ingress controller's TLS certificate expiration date stored in the cluster secret store in this context"], correct:0, explanation:"The Kubernetes audit log records API requests with user, verb, and resource, exposing unauthorized actions. Image lists, fan telemetry, and cert expiry dates do not track API activity." },
  { id:70770, domain:5, level:2, question:"Which sign in a firewall log most strongly suggests port scanning from an external source?", options:["A single external IP establishing one long authenticated session to the mail server port","Repeated denied connection attempts from one external IP across many sequential ports","Steady permitted HTTPS traffic from many customers to the public web server address","Periodic outbound NTP requests from internal hosts to the configured time server pool"], correct:1, explanation:"Denied attempts across many sequential ports from one source indicate scanning. A single authenticated session, normal customer HTTPS, and internal NTP are legitimate patterns." },
  { id:70771, domain:5, level:2, question:"Which statement about chain of custody applies equally to network and cloud evidence?", options:["It is optional whenever the evidence originates from a cloud provider's managed service","It applies only to physical hard drives and never to log exports or packet captures","It must document who collected, handled, and stored the evidence and when at each step","It requires deleting the original evidence once a working copy has been made for analysis"], correct:2, explanation:"Chain of custody documents handling at every step for all evidence types. It is never optional, applies beyond physical drives, and originals must be preserved, not deleted." },
  { id:70772, domain:5, level:1, question:"Which protocol is most commonly forged or exploited in DNS-based attacks such as cache poisoning?", options:["The Simple Mail Transfer Protocol used to relay email messages between mail servers","The Network Time Protocol used to synchronize system clocks against reference sources","The Dynamic Host Configuration Protocol used to assign IP addresses to network clients","The Domain Name System protocol that resolves human-readable names into IP addresses"], correct:3, explanation:"DNS cache poisoning targets the Domain Name System protocol. SMTP relays mail, NTP synchronizes time, and DHCP assigns addresses, none of which is the subject of cache poisoning." },
  { id:70773, domain:5, level:3, question:"An analyst wants to detect covert exfiltration hidden in ICMP traffic. Which observation is most suspicious?", options:["Large or numerous ICMP echo packets carrying unusual high-entropy data in their payloads","Occasional small echo requests used by monitoring tools to check host reachability quickly","A single traceroute producing the expected sequence of TTL-expired responses along a path","Standard path MTU discovery messages reporting fragmentation-needed conditions on a link"], correct:0, explanation:"Large ICMP packets with high-entropy payloads suggest data smuggled in ICMP tunneling. Small reachability pings, normal traceroutes, and PMTU messages are ordinary ICMP behavior." },
  { id:70774, domain:5, level:2, question:"Which cloud acquisition consideration is unique to PaaS compared with IaaS?", options:["In PaaS the customer manages the guest operating system and can image the full virtual disk in this context","In PaaS the underlying OS and runtime are provider-managed, limiting direct disk-level access","In PaaS there are never any application logs available for the customer to review or export","In PaaS the customer always receives physical access to the datacenter hosting the platform"], correct:1, explanation:"In PaaS the provider manages the OS and runtime, so customers lack disk-level access. Customers do not manage the guest OS, application logs usually exist, and physical access is never granted." },
  { id:70775, domain:5, level:2, question:"Which detail in Wireshark best confirms that observed traffic is a genuine TCP retransmission rather than a duplicate capture?", options:["The packet's frame number is simply higher than every other packet in the capture file in this context","The packet uses a source port that falls within the well-known port number range only","Wireshark's Expert Info flags it as a retransmission based on sequence and acknowledgment analysis","The packet was captured on a Tuesday according to the system clock of the capture host"], correct:2, explanation:"Wireshark's Expert Info analyzes sequence/ack numbers to identify retransmissions. Frame number order, port range, and capture day do not determine retransmission versus duplication." },
  { id:70776, domain:5, level:3, question:"During a multi-tenant cloud breach, why must an investigator be careful when acquiring a snapshot of shared storage?", options:["Snapshots of shared storage are impossible to create because the data changes too rapidly","Snapshots automatically encrypt and permanently destroy the tenant's own data upon creation","Shared storage snapshots always exclude the target tenant's data, making them useless entirely","The snapshot may contain other tenants' data, raising privacy and legal admissibility concerns"], correct:3, explanation:"Shared-storage snapshots risk capturing other tenants' data, creating privacy and admissibility issues. Snapshots are feasible, do not destroy data, and do include the target's data." },
  { id:70777, domain:5, level:2, question:"Which log entry pattern in web server logs is a hallmark of a directory traversal attempt?", options:["A request path containing repeated ../ sequences aiming to reach files outside the web root","A request for the site's favicon.ico icon served with a normal 200 status response code","A conditional GET with an If-Modified-Since header returning a 304 not modified response in this context","A HEAD request that retrieves only the response headers without any accompanying body"], correct:0, explanation:"Repeated ../ sequences trying to escape the web root mark directory traversal. Favicon requests, conditional GETs, and HEAD requests are routine, legitimate HTTP behaviors." },
  { id:70778, domain:5, level:1, question:"What is the primary evidentiary value of a full PCAP file in an investigation?", options:["It records only the total number of bytes transferred without any detailed packet content in this context","It preserves complete packet contents, enabling later reconstruction of the communications","It stores just the source and destination IP addresses of each observed conversation flow","It contains only summarized alerts generated by an intrusion detection sensor over time"], correct:1, explanation:"A full PCAP preserves complete packets, allowing communication reconstruction. It is not merely a byte counter, an address-only summary, or a collection of IDS alerts." },
  { id:70779, domain:5, level:2, question:"Which factor makes attributing cloud-based attacks especially difficult for investigators?", options:["Cloud providers always publish the real names of every user who launches any instance","Every cloud action is automatically tied to a verified government-issued identity document","Attackers can use ephemeral instances, stolen credentials, and shared IPs to obscure identity","Cloud instances can never change their public IP addresses throughout their entire lifetime in this context"], correct:2, explanation:"Ephemeral instances, stolen credentials, and shared IPs frustrate attribution. Providers do not publish real user names, actions are not tied to verified IDs, and IPs can change." },
  { id:70780, domain:5, level:3, question:"An investigator correlates a spike in outbound traffic with a scheduled task creation on an endpoint. What conclusion is best supported?", options:["The two events are certainly unrelated and should be documented in completely separate cases in this context","The outbound spike proves the endpoint was patched successfully during a maintenance window","The scheduled task is guaranteed to be a legitimate backup job requiring no further review","Persistence via the scheduled task may be driving the periodic outbound exfiltration or beacon"], correct:3, explanation:"A scheduled task coinciding with periodic outbound traffic suggests persistence driving beaconing. Dismissing them as unrelated, patching evidence, or a guaranteed backup are unjustified conclusions." },
  { id:70781, domain:5, level:2, question:"Which of the following is the best reason to preserve NetFlow data even when full packet capture is unavailable?", options:["NetFlow offers a compact, long-retained record of conversations useful for scoping incidents","NetFlow contains the full decrypted payload of every session, making capture redundant in this context","NetFlow automatically identifies the attacker's real-world legal name and home address","NetFlow blocks malicious connections in real time before they can reach internal hosts"], correct:0, explanation:"NetFlow provides compact, long-retained conversation records ideal for scoping. It has no payloads, cannot reveal a legal identity, and is a passive record, not a blocking control." },
  { id:70782, domain:5, level:1, question:"Which AWS log records network-level connection metadata within a virtual private cloud?", options:["AWS Config, which records the configuration state and change history of AWS resources in this context","VPC Flow Logs, which capture accepted and rejected IP traffic metadata for network interfaces","Amazon Route 53 logs, which record DNS queries resolved by hosted zones for domains","AWS Trusted Advisor, which offers best-practice recommendations for cost and security"], correct:1, explanation:"VPC Flow Logs capture IP traffic metadata for interfaces. Config tracks resource configuration, Route 53 logs DNS queries, and Trusted Advisor gives recommendations, not flow data." },
  { id:70783, domain:5, level:2, question:"An analyst finds that a captured session used a self-signed certificate for an internal banking site. What does this most likely suggest?", options:["The site upgraded to the latest extended-validation certificate issued by a trusted authority","Nothing unusual, because self-signed certificates are the recommended standard for banks","A possible interception or spoofing attempt, since legitimate banking sites use trusted CAs","A confirmed hardware failure in the client's network interface card during the TLS handshake"], correct:2, explanation:"A self-signed cert on a banking site suggests interception or spoofing since real banks use trusted CAs. It is not an EV upgrade, not recommended practice, and not a NIC failure." },
  { id:70784, domain:5, level:3, question:"Which approach best determines whether inbound web traffic represents a real DDoS or a flash crowd of legitimate users?", options:["Assuming any traffic increase is malicious and immediately blackholing the entire network","Rebooting the web server repeatedly until the traffic volume returns to its normal baseline","Ignoring the traffic entirely because web servers are designed to handle unlimited load","Analyzing source diversity, request validity, session behavior, and correlation with events"], correct:3, explanation:"Analyzing source diversity, request validity, and behavior distinguishes DDoS from flash crowds. Blanket blocking, rebooting, and ignoring the traffic are not sound investigative methods." },
  { id:70785, domain:5, level:2, question:"Which email authentication record, when failing, may indicate a spoofed sending domain during email tracing?", options:["An SPF record failure, indicating the sending server was not authorized by the domain owner","An MX record absence, indicating the domain simply has no mail exchanger configured at all in this context","A CNAME record mismatch, indicating a website alias points to an unexpected canonical name","A TXT record length, indicating the domain stores a longer than average descriptive string"], correct:0, explanation:"An SPF failure means the sending server is not authorized, a spoofing indicator. Missing MX, CNAME mismatches, and TXT length are unrelated to sender authorization for a message." },
  { id:70786, domain:5, level:1, question:"What is the main forensic purpose of examining a web server's error log alongside its access log?", options:["To determine the physical temperature of the server room during the incident timeframe","To reveal failed requests, application errors, and traces of exploitation attempts","To measure the exact electrical power the server consumed while handling each request","To list the names of all employees who have physical keycard access to the datacenter"], correct:1, explanation:"Error logs reveal failed requests and exploitation traces complementing access logs. They do not report room temperature, power consumption, or datacenter keycard access rosters." },
  { id:70787, domain:5, level:3, question:"An investigator must show an attacker pivoted from a web server to a database server. Which evidence chain is most convincing?", options:["The web server's uptime counter alone, showing it had been running for many days total","A vendor brochure describing the database product's supported authentication mechanisms","Web shell activity on the web server correlated with new DB connections and query logs","The database administrator's personal opinion that a pivot probably occurred at some point"], correct:2, explanation:"Web shell activity correlated with new DB connections and query logs proves the pivot. An uptime counter, a product brochure, and an unsupported opinion do not establish the pivot chain." },
  { id:70788, domain:5, level:2, question:"Which cloud-native artifact best shows that an S3 bucket was made publicly accessible by a configuration change?", options:["A CloudWatch alarm reporting elevated network throughput on an unrelated compute instance in this context","A Route 53 health check reporting that a monitored web endpoint returned a healthy status","An EC2 instance's system log showing the guest operating system boot messages at startup","A CloudTrail PutBucketAcl or PutBucketPolicy event recording the permission change and caller"], correct:3, explanation:"A CloudTrail PutBucketAcl/PutBucketPolicy event captures the permission change and who made it. Throughput alarms, health checks, and OS boot logs do not record the bucket policy change." },
  { id:70789, domain:5, level:2, question:"Which behavior distinguishes a slow-and-low data exfiltration from a bulk transfer in flow analysis?", options:["Small amounts of data leaving steadily over a long period to blend in with normal traffic","A single very large transfer completing in seconds during a well-known backup maintenance window","Thousands of inbound customer connections to the public web server during a sales event","A short burst of internal file-share traffic between two servers on the same fast subnet"], correct:0, explanation:"Slow-and-low exfiltration trickles small amounts over time to evade thresholds. A single large backup, inbound customer traffic, and brief internal transfers are not slow-and-low patterns." },
  { id:70790, domain:5, level:1, question:"What does a proxy server sit between in a typical enterprise deployment?", options:["Between two hard drives to mirror data for redundancy within a single storage array","Between internal clients and external servers, mediating and often logging their requests","Between a CPU and its memory to accelerate arithmetic operations inside the processor","Between two power supplies to balance electrical load across redundant feeds in a rack in this context"], correct:1, explanation:"A proxy mediates between internal clients and external servers, often logging requests. It is not a disk mirror, a CPU-memory intermediary, or a power-balancing device." },
  { id:70791, domain:5, level:3, question:"An analyst sees TCP sessions where the client sends data but the server's ACKs come from a different MAC than earlier. What should be suspected?", options:["A normal load-balancer behavior that always rewrites Layer 2 addresses for every packet","A benign duplicate ACK caused by minor packet reordering on a congested network link","An active man-in-the-middle where an attacker inserted itself into the session path","A routine DHCP renewal that temporarily changed the client's assigned IP address lease"], correct:2, explanation:"A changed responder MAC mid-session suggests an active MITM inserted in the path. Load balancers do not arbitrarily rewrite MACs per packet, duplicate ACKs and DHCP renewals differ." },
  { id:70792, domain:5, level:2, question:"Which of the following is the most appropriate first step when preserving a live network intrusion in progress?", options:["Immediately power off every affected server to stop the attacker from doing more damage in this context","Delete the suspicious log files so the attacker cannot cover their tracks any further","Reinstall the operating system on the compromised hosts before analyzing any evidence","Begin capturing traffic and collecting volatile data while documenting each action taken"], correct:3, explanation:"Capturing traffic and volatile data with documentation preserves evidence during a live incident. Powering off, deleting logs, and reinstalling all destroy valuable volatile evidence." },
  { id:70793, domain:5, level:2, question:"Which characteristic of Azure Monitor makes it valuable for cloud incident investigation?", options:["It centralizes metrics and logs from Azure resources for querying and alerting during analysis","It physically shreds decommissioned disks in the datacenter according to a fixed schedule","It exclusively manages billing invoices and never surfaces any operational or security telemetry","It only functions for on-premises Windows servers and cannot observe any cloud resources"], correct:0, explanation:"Azure Monitor centralizes metrics and logs for querying and alerting. It does not shred disks, is not a billing-only tool, and observes cloud resources, not just on-prem servers." },
  { id:70794, domain:5, level:3, question:"An investigator finds that logs on a compromised host were cleared, but the SIEM still holds copies. Why is this significant?", options:["It means the investigation must stop because the primary host logs are permanently gone in this context","Centralized log forwarding preserved evidence beyond the attacker's reach on the local host","It proves conclusively that no attacker was ever present on the host in the first place","It indicates the SIEM itself was the origin of the attack against the compromised host"], correct:1, explanation:"Forwarding logs to a SIEM preserves them despite local clearing, defeating anti-forensics. It does not halt the case, disprove intrusion, or implicate the SIEM as the attacker." },
  { id:70795, domain:5, level:2, question:"Which observation in wireless capture most clearly indicates a WPA2 handshake suitable for offline analysis was captured?", options:["A series of beacon frames advertising the SSID at the standard broadcast interval only in this context","A single deauthentication frame with no subsequent reassociation attempt by any client","The presence of all four EAPOL key-exchange messages between the client and access point","A broadcast ARP request from the client seeking the MAC address of the default gateway"], correct:2, explanation:"All four EAPOL messages constitute the complete WPA2 handshake needed offline. Beacons, a lone deauth, and an ARP request do not contain the key-exchange material." },
  { id:70796, domain:5, level:1, question:"What type of evidence does a SIEM primarily correlate?", options:["Physical fingerprints lifted from keyboards and hardware surfaces at a crime scene","Only the contents of employees' personal email accounts stored on external providers","Exclusively video surveillance footage from cameras positioned around a facility site","Log and event data aggregated from many systems to detect patterns across sources"], correct:3, explanation:"A SIEM correlates log and event data from many systems. It does not process physical fingerprints, personal email contents, or surveillance video as its primary inputs." },
  { id:70797, domain:5, level:2, question:"Which detail from a captured HTTP request header can help identify the specific client software involved in an attack?", options:["The User-Agent header, which reports the browser, application, or tool making the request","The Content-Length header, which reports only the size in bytes of the request message body","The Connection header, which indicates whether the TCP connection should be kept alive","The Accept-Encoding header, which lists the compression schemes the client can decode"], correct:0, explanation:"The User-Agent identifies the client software or tool. Content-Length gives body size, Connection controls keep-alive, and Accept-Encoding lists compression support, not client identity." },
  { id:70798, domain:5, level:3, question:"When reconstructing a phishing-driven intrusion, why is correlating email gateway logs with proxy logs important?", options:["It confirms the datacenter's cooling system operated within its normal temperature range","It links the delivered malicious link to the user's subsequent click and connection attempt","It measures the total electricity consumed by the mail server during the incident window","It verifies the office building's fire suppression system was inspected on schedule recently"], correct:1, explanation:"Correlating email gateway and proxy logs links delivery of the link to the user's click. It has nothing to do with cooling, electricity consumption, or fire suppression inspections." },
  { id:70799, domain:5, level:2, question:"Which of the following best describes IPFIX in relation to NetFlow?", options:["IPFIX is an unrelated protocol for encrypting flow records that has no ties to NetFlow","IPFIX is a proprietary Microsoft protocol that only functions within Windows Server domains","IPFIX is an IETF standard flow-export protocol derived largely from Cisco NetFlow version 9","IPFIX is a physical cabling standard defining connector pinouts for high-speed network links"], correct:2, explanation:"IPFIX is the IETF-standardized flow-export protocol based on NetFlow v9. It is not an encryption scheme, a Microsoft-only protocol, or a physical cabling standard." },
  { id:70800, domain:5, level:1, question:"What is the purpose of packet reassembly in network forensic tools?", options:["To physically repair damaged network cables that caused packet loss during transmission in this context","To assign new IP addresses to hosts that lost their leases during the capture window","To compress the capture file so it consumes less storage space on the analysis system","To combine fragmented or segmented packets back into complete application-layer messages"], correct:3, explanation:"Reassembly reconstructs complete application messages from fragments/segments. It does not repair cables, assign IP addresses, or compress the capture file." },
  { id:70801, domain:5, level:3, question:"An investigator needs to prove a specific user account performed a destructive action in AWS. Which CloudTrail field is most critical?", options:["The userIdentity element, which records the principal, account, and access key behind the call","The eventTime alone, which records only when some unspecified event happened in the account in this context","The awsRegion field, which records only the geographic region where the API call was served","The eventVersion field, which records only the schema version of the log record structure"], correct:0, explanation:"The userIdentity element identifies the principal and credentials behind the call, proving attribution. eventTime, awsRegion, and eventVersion give timing, location, and schema, not identity." },
  { id:70802, domain:5, level:2, question:"Which pattern in proxy logs most strongly suggests a user's browser was redirected to a malicious site via a compromised ad network?", options:["A direct navigation to a well-known banking domain typed manually into the address bar","A chain of automatic redirects ending at an unfamiliar domain serving suspicious content","A single request for a company intranet page returning a normal successful status code","A cached image reload from a trusted CDN with a conditional not-modified server response"], correct:1, explanation:"A redirect chain landing on an unfamiliar suspicious domain suggests malvertising redirection. Direct banking navigation, intranet requests, and cached CDN reloads are ordinary activity." },
  { id:70803, domain:5, level:2, question:"Which tool feature helps an investigator extract transferred files directly from a PCAP?", options:["Wireshark's Coloring Rules, which only change the on-screen background color of matching packets in this context","Wireshark's Time Shift feature, which merely adjusts the recorded timestamps of selected packets","Wireshark's Export Objects function, which reconstructs and saves files carried over supported protocols","Wireshark's Capture Filter, which limits what is recorded but cannot extract any stored files"], correct:2, explanation:"Export Objects reconstructs and saves files from supported protocols in a capture. Coloring Rules, Time Shift, and Capture Filters do not extract transferred files from the PCAP." },
  { id:70804, domain:5, level:1, question:"Which of the following is an example of IaaS evidence a customer can typically acquire?", options:["The physical motherboard of the exact server blade running the customer's virtual machine","The provider's internal datacenter access badge logs for all facility staff members","The source code of the cloud hypervisor that the provider uses to run tenant workloads","A disk snapshot and memory image of the customer's own virtual machine instance"], correct:3, explanation:"In IaaS a customer controls the VM and can snapshot its disk and memory. The physical hardware, provider staff badge logs, and hypervisor source code are provider-owned and inaccessible." },
  { id:70805, domain:5, level:3, question:"An analyst observes encrypted traffic to a known malicious IP but cannot decrypt it. Which forensic conclusion is still defensible?", options:["A connection to a known malicious endpoint occurred, supporting compromise even without payload","The exact commands the attacker issued can be fully recovered from the encrypted stream","The user's plaintext password was definitely transmitted and can be read from the capture","No evidentiary value exists at all because the traffic contents cannot be directly decrypted in this context"], correct:0, explanation:"Even without decryption, contact with a known malicious IP supports a compromise finding. You cannot recover commands or passwords from ciphertext, but the metadata still has value." },
  { id:70806, domain:5, level:2, question:"Which log is the best source to confirm the time and source of a brute-force login attack against a web application?", options:["The DNS resolver log recording forward lookups for unrelated external domain names","The application authentication log recording repeated failed logins with source IP and timestamps","The NTP log recording the clock offset adjustments made against upstream time servers","The DHCP log recording the address leases granted to clients joining the local network in this context"], correct:1, explanation:"The application auth log records failed logins with source IP and time, confirming brute force. DNS, NTP, and DHCP logs record name resolution, time sync, and addressing, not logins." },
  { id:70807, domain:5, level:2, question:"Which statement about volatile versus non-volatile evidence in network forensics is correct?", options:["Active connection tables are non-volatile and survive indefinitely after a host is powered off","All network evidence is equally volatile and disappears the instant a capture session ends","Active connections and memory are volatile, while archived logs on disk are non-volatile","Non-volatile evidence must always be collected before any volatile evidence in every case"], correct:2, explanation:"Active connections and memory are volatile; archived disk logs are non-volatile. Connection tables do not survive power-off, not all evidence is equally volatile, and volatile data is collected first." },
  { id:70808, domain:5, level:1, question:"What does an evil twin access point rely on to deceive victims?", options:["A physically identical hardware casing that matches the legitimate access point exactly","A stolen administrator password required to reconfigure every nearby client device","A signed firmware update pushed silently to every client on the wireless network","A matching or similar SSID that makes clients believe it is the legitimate network"], correct:3, explanation:"An evil twin uses a matching SSID to trick clients into connecting. It does not depend on identical casing, stealing admin passwords, or pushing firmware updates to clients." },
  { id:70809, domain:5, level:3, question:"An investigator must determine whether outbound HTTPS to a cloud storage service was authorized exfiltration or normal use. What best supports the determination?", options:["Correlating the traffic with DLP alerts, user role, data classification, and business context","The color scheme of the cloud storage provider's login page seen in a browser screenshot","The total number of bytes only, since any large upload is automatically malicious exfiltration","The provider's uptime statistics for the storage service during the investigation timeframe"], correct:0, explanation:"Correlating with DLP alerts, user role, data sensitivity, and context distinguishes exfiltration from legitimate use. Page color, byte count alone, and uptime stats cannot make that call." },
  { id:70810, domain:5, level:2, question:"Which detail in an IIS log field set records the client's IP address that made the request?", options:["The cs-uri-stem field, which records the requested resource path without the query string","The c-ip field, which records the IP address of the client that submitted the HTTP request","The sc-status field, which records the numeric HTTP status the server returned to the client","The cs-method field, which records the HTTP method such as GET or POST used in the request"], correct:1, explanation:"In IIS logs, c-ip is the client IP. cs-uri-stem is the requested path, sc-status is the response code, and cs-method is the HTTP verb, none of which is the client address." },
  { id:70811, domain:5, level:2, question:"Which observation would most strongly indicate a compromised host is participating in a botnet?", options:["The host regularly synchronizes its clock with an internal NTP server every few minutes","The host downloads routine operating system updates from the vendor's signed update servers in this context","The host maintains persistent connections to known C2 infrastructure and relays coordinated traffic","The host prints documents to the departmental printer during standard business hours daily"], correct:2, explanation:"Persistent C2 connections with coordinated traffic indicate botnet participation. NTP sync, signed OS updates, and printing are ordinary, legitimate host behaviors." },
  { id:70812, domain:5, level:1, question:"What is the main advantage of centralized logging for network forensics?", options:["It guarantees that no attacker can ever gain access to any system on the network","It eliminates the need to ever synchronize clocks between the participating devices","It automatically encrypts all network traffic between clients and servers by default in this context","It aggregates logs from many sources, aiding correlation and protecting them from local tampering"], correct:3, explanation:"Centralized logging aggregates sources for correlation and resists local tampering. It does not prevent all access, remove the need for time sync, or encrypt live network traffic." },
  { id:70813, domain:5, level:3, question:"An analyst finds gaps in packet captures during peak traffic. What is the most likely forensic implication?", options:["Packet drops from capture overload may leave gaps, so findings should note incomplete coverage","The captured evidence is entirely worthless and must be discarded from the case immediately in this context","The gaps prove the attacker deliberately deleted individual packets from the capture file","The gaps confirm that no attack occurred during the periods where packets are missing"], correct:0, explanation:"Capture overload causes drops, so analysts should document incomplete coverage. The evidence is not worthless, gaps are not attacker deletions, and absence of packets does not disprove an attack." },
  { id:70814, domain:5, level:2, question:"Which cloud service log would best show that an attacker disabled logging to evade detection?", options:["A CloudWatch dashboard widget configuration that changed the color of a displayed graph in this context","A CloudTrail StopLogging or DeleteTrail event recorded before the logging pipeline stopped","An S3 lifecycle transition moving an object to a colder storage tier after ninety days","A Route 53 record update changing the IP address associated with a hosted domain name"], correct:1, explanation:"A CloudTrail StopLogging or DeleteTrail event captured before logging halted reveals evasion. Dashboard colors, lifecycle transitions, and DNS record changes are unrelated to disabling logging." },
  { id:70815, domain:5, level:2, question:"Which sign in DNS logs is characteristic of a fast flux network used by malware?", options:["A single stable A record that maps the domain to one IP address for many months at a time in this context","A reverse PTR lookup returning the expected hostname for an internal server's IP address","A single domain resolving to many rapidly changing IP addresses with very short TTL values","A routine SOA record query returning the authoritative zone's serial and refresh values"], correct:2, explanation:"Fast flux rotates a domain across many IPs with short TTLs. A stable single A record, normal PTR lookups, and routine SOA queries are not indicative of fast flux behavior." },
  { id:70816, domain:5, level:1, question:"What is the role of a write blocker in the network forensics workflow?", options:["It captures live packets from a mirrored switch port for real-time protocol analysis","It correlates events across firewalls and endpoints to build an attack-sequence timeline in this context","It assigns IP addresses to investigation workstations connecting to the evidence network","It prevents accidental modification of source media during the imaging of stored evidence"], correct:3, explanation:"A write blocker prevents modifying source media during imaging. It does not capture packets, correlate events, or assign IP addresses, which are separate tools and functions." },
  { id:70817, domain:5, level:3, question:"When investigating a suspected insider exfiltration to personal cloud storage, why are proxy and DNS logs together more powerful than either alone?", options:["DNS logs reveal the resolved destinations while proxy logs confirm the sessions and data volumes","Proxy logs alone always contain the decrypted file contents, making DNS logs redundant here in this context","DNS logs record the exact file names uploaded, so proxy logs add nothing to the analysis","Proxy logs record the employee's home address, which DNS logs are unable to ever provide"], correct:0, explanation:"DNS shows which destinations were resolved and proxy confirms sessions and volumes; together they corroborate. Proxy logs lack decrypted contents, DNS lacks file names, and neither reveals a home address." },
  { id:70818, domain:5, level:2, question:"Which of the following best characterizes a SYN flood attack observed in a packet capture?", options:["A steady stream of completed three-way handshakes followed by legitimate data transfers","A flood of SYN packets with no completing ACKs, exhausting the target's connection table","A single large file download from one source consuming most of the available bandwidth","A burst of ICMP echo requests used by an administrator to verify host reachability quickly"], correct:1, explanation:"A SYN flood sends many SYNs without completing ACKs to exhaust connection tables. Completed handshakes, a single download, and ICMP pings are not SYN flood signatures." },
  { id:70819, domain:5, level:2, question:"Which cloud evidence source is most relevant when investigating unauthorized changes to Azure network security groups?", options:["The Azure Blob Storage access tier setting that determines hot versus cool storage pricing in this context","The Azure Cost Management report summarizing monthly spending across the subscriptions","The Azure Activity Log recording the network security group rule modification and its initiator","The Azure Advisor recommendation list suggesting best practices for cost optimization"], correct:2, explanation:"The Azure Activity Log records NSG rule changes and who made them. Storage tiers, cost reports, and Advisor recommendations do not record security group modifications." },
  { id:70820, domain:5, level:1, question:"What does the term lateral movement describe in a network intrusion?", options:["An attacker downloading a larger version of the malware from an external hosting site","An administrator physically relocating servers from one datacenter rack to another rack","A user switching between multiple browser tabs while working on an internal web application","An attacker moving through internal systems to expand access after an initial foothold"], correct:3, explanation:"Lateral movement is spreading through internal systems after initial access. It is not downloading larger malware, moving physical servers, or switching browser tabs." },
  { id:70821, domain:5, level:3, question:"An investigator needs to demonstrate the integrity of a captured PCAP over months of storage. Which practice is most important?", options:["Computing and recording a cryptographic hash of the file at collection and verifying it later","Storing the capture on a shared drive that many analysts can freely edit during review","Renaming the file periodically so its name reflects the most recent analyst who opened it in this context","Compressing and recompressing the file repeatedly to save space on the evidence server"], correct:0, explanation:"Hashing at collection and re-verifying proves integrity over time. Editable shared storage, repeated renaming, and recompression risk altering or obscuring the evidence's integrity." },
  { id:70822, domain:5, level:2, question:"Which observation would most likely indicate a web shell is being used interactively by an attacker?", options:["A series of GET requests for the site's standard CSS and JavaScript static asset files","Repeated POST requests to an obscure script with command-like parameters and varied outputs","A single successful login to the site's legitimate content management admin dashboard","Conditional requests for images returning not-modified responses to a returning visitor in this context"], correct:1, explanation:"Repeated POSTs to an obscure script with command parameters signal interactive web shell use. Static asset GETs, a normal admin login, and cached image checks are ordinary traffic." },
  { id:70823, domain:5, level:2, question:"Why might an investigator prefer capturing at a network aggregation point rather than a single endpoint?", options:["An aggregation point automatically decrypts all TLS sessions passing through the network core in this context","A single endpoint capture always contains the traffic of every other host on the network","An aggregation point can observe traffic among many hosts, giving broader visibility of activity","An aggregation point removes the need to synchronize clocks across the monitored devices"], correct:2, explanation:"Aggregation points see many hosts' traffic, giving broad visibility. They do not auto-decrypt TLS, a single endpoint sees only its own traffic, and time sync is still needed." },
  { id:70824, domain:5, level:1, question:"What is the primary function of AWS CloudTrail?", options:["To store and serve large binary objects such as images and backup archives for applications in this context","To distribute cached web content to edge locations physically close to end users worldwide","To provide managed relational database engines with automated backups and failover support","To record account activity and API calls for governance, compliance, and operational auditing"], correct:3, explanation:"CloudTrail records API calls and account activity for auditing. Object storage is S3, content distribution is CloudFront, and managed databases are RDS, not CloudTrail." },
  { id:70825, domain:5, level:3, question:"An analyst correlates a firewall allow event, an IDS exploit alert, and a new outbound connection within seconds. What is the best interpretation?", options:["A likely successful exploitation followed by attacker callback, forming a coherent attack chain","The three events are coincidental and should each be filed as separate unrelated observations","The firewall must be malfunctioning because it allowed traffic that the IDS also observed","The IDS alert alone proves nothing since network defenses always generate false positives only in this context"], correct:0, explanation:"An allow, an exploit alert, and an immediate outbound callback in seconds form a coherent attack chain. Treating them as coincidental, blaming the firewall, or dismissing the IDS ignores the correlation." },
  { id:70826, domain:5, level:2, question:"Which of the following is a legitimate reason network time synchronization is emphasized in cloud and hybrid investigations?", options:["Synchronized time automatically encrypts every log entry generated across all environments in this context","Synchronized time lets events from cloud and on-premises logs be ordered on one accurate timeline","Synchronized time prevents attackers from ever authenticating to any cloud service at all","Synchronized time reduces the storage each log file consumes on the collection server"], correct:1, explanation:"Synchronized clocks allow cloud and on-prem events to align on one timeline. Time sync does not encrypt logs, block authentication, or reduce log storage size." },
  { id:70827, domain:5, level:2, question:"Which artifact best confirms that a specific external IP conducted a port scan against a DMZ host?", options:["The DMZ host's desktop wallpaper image chosen by the administrator during initial setup","The vendor documentation describing the default open ports for the installed web server","Firewall or IDS logs showing sequential connection attempts to many ports from that IP","The DMZ host's uptime counter indicating how long it has run since its last reboot event"], correct:2, explanation:"Firewall/IDS logs of sequential port attempts from an IP confirm scanning. Wallpaper, vendor docs, and uptime counters provide no evidence of a scan from that source." },
  { id:70828, domain:5, level:1, question:"What is a PCAP file primarily used for?", options:["Encrypting network traffic between two endpoints using a negotiated session key","Assigning IP addresses dynamically to hosts as they connect to the network segment","Blocking malicious connections in real time before they reach protected internal hosts","Storing captured network packets for later inspection and analysis by forensic tools"], correct:3, explanation:"A PCAP stores captured packets for later analysis. It does not encrypt traffic, assign addresses, or block connections, which are functions of other technologies entirely." },
  { id:70829, domain:5, level:3, question:"An investigator suspects an attacker used a stolen API key in a cloud environment. Which evidence most directly supports attribution to that key?", options:["Audit log entries recording the access key ID used for each API call along with source IP","The provider's public status page showing that the region experienced no outages that day","The billing dashboard total showing the overall monthly spend across the account services","The marketing description of the cloud provider's security certifications and compliance"], correct:0, explanation:"Audit logs tying the access key ID to each API call and source IP directly support attribution. A status page, billing totals, and compliance marketing do not identify the key used." },
  { id:70830, domain:5, level:2, question:"Which behavior most clearly distinguishes exfiltration over DNS from ordinary DNS resolution?", options:["Occasional lookups of common domains returning cached answers with normal TTL durations in this context","A high volume of TXT or long subdomain queries encoding data to one authoritative server","Standard A and AAAA lookups for popular websites during normal business working hours","Reverse PTR queries mapping a handful of internal IP addresses back to their hostnames"], correct:1, explanation:"High-volume TXT or long-subdomain queries to one server encode exfiltrated data. Cached common lookups, standard A/AAAA queries, and a few PTR lookups are ordinary DNS resolution." },
  { id:70831, domain:5, level:2, question:"Which log detail helps an investigator determine whether an outbound connection used a proxy or went direct?", options:["The printer spooler log listing which documents each workstation submitted for printing","The NTP daemon log recording the offset corrections applied against upstream time sources in this context","The proxy access log showing the internal client, the requested URL, and the upstream request","The screen resolution reported by the client workstation's display adapter configuration"], correct:2, explanation:"The proxy access log records the internal client and its proxied requests, showing proxy use. Printer spooler, NTP, and screen resolution data reveal nothing about the connection path." },
  { id:70832, domain:5, level:1, question:"What does the term rogue DHCP server refer to?", options:["An authorized DHCP server that has been correctly registered and documented in the inventory","A DHCP server kept powered off in storage as a spare for disaster recovery scenarios","A DNS server that answers name resolution queries for internal clients on the network","An unauthorized server handing out IP configuration, potentially misdirecting client traffic"], correct:3, explanation:"A rogue DHCP server is unauthorized and can misdirect clients via bad configuration. An authorized inventoried server, an offline spare, and a DNS server are not rogue DHCP servers." },
  { id:70833, domain:5, level:3, question:"An analyst needs to prove that captured wireless traffic belongs to a specific target network and not a neighbor. Which detail is most conclusive?", options:["The BSSID (access point MAC) and SSID matching the documented target network identifiers","The overall signal strength reading, since the strongest signal always belongs to the target","The time of day the capture was taken, since neighbors only use their networks at night","The channel width setting, since all neighboring networks use a completely different width"], correct:0, explanation:"Matching the BSSID and SSID to documented target identifiers conclusively ties traffic to the network. Signal strength, time of day, and channel width are not reliable ownership indicators." },
  { id:70834, domain:5, level:2, question:"Which of the following is the best description of NetFlow's limitation for deep forensic analysis?", options:["NetFlow captures full packet payloads, making it too large to store for any useful period","NetFlow records only conversation metadata, so it cannot reveal the actual data contents","NetFlow works exclusively on wireless networks and cannot observe any wired traffic flows","NetFlow can only be collected from cloud environments and never from on-premises routers"], correct:1, explanation:"NetFlow records metadata only, so payload contents are unavailable. It does not capture payloads, works on wired networks, and can be collected from on-premises routers." },
  { id:70835, domain:5, level:2, question:"Which observation in web logs is the clearest indicator of a successful SQL injection that returned data?", options:["A normal 404 response for a mistyped page path requested once by an ordinary site visitor","A conditional GET for a stylesheet returning a not-modified response to a returning client","A crafted parameter with SQL syntax returning a 200 with an abnormally large response body","A routine POST to the contact form returning a standard confirmation page to the sender"], correct:2, explanation:"A SQL-laden parameter returning 200 with an oversized body suggests successful data extraction. A 404, a cached stylesheet check, and a normal contact form post are benign events." },
  { id:70836, domain:5, level:1, question:"What is the primary purpose of an IDS signature?", options:["To encrypt the payload of packets as they traverse the monitored network segment securely in this context","To assign priority levels to voice and video packets crossing a congested network link","To allocate IP addresses to clients as they join and leave the monitored network segment","To define a pattern that, when matched in traffic, triggers an alert about known malicious activity"], correct:3, explanation:"An IDS signature defines a pattern that triggers alerts on known malicious traffic. It does not encrypt packets, prioritize QoS, or allocate IP addresses to clients." },
  { id:70837, domain:5, level:3, question:"An investigator finds that a cloud instance's memory was never captured before termination. What is the most accurate assessment?", options:["Volatile evidence in memory, such as decryption keys and running processes, is likely lost","The disk snapshot alone always contains a perfect copy of everything that was in memory","Memory evidence is irrelevant in cloud cases because only disk artifacts ever matter there","The instance can always be restarted to recover the exact prior contents of its memory"], correct:0, explanation:"Terminating without a memory dump loses volatile data like keys and process state. Disk snapshots do not contain memory, memory can be crucial, and restarting yields fresh, not prior, memory." },
  { id:70838, domain:5, level:2, question:"Which characteristic of GCP audit logs should an investigator understand before relying on Data Access logs?", options:["Data Access logs are enabled by default for all services and always capture every read event","Data Access logs are often disabled by default and may need to be enabled to capture reads","Data Access logs record only administrative configuration changes and never any data reads","Data Access logs are stored exclusively on-premises and are unavailable within the cloud"], correct:1, explanation:"GCP Data Access logs are frequently off by default and must be enabled to capture reads. They are not on by default, do cover reads (not just admin actions), and are stored in the cloud." },
  { id:70839, domain:5, level:2, question:"Which of the following best explains why an investigator would follow a TCP stream in Wireshark?", options:["To change the display color of every packet belonging to that particular conversation flow in this context","To permanently delete the selected packets from the capture file to reduce its total size","To reassemble the bidirectional payload and read the application-layer conversation content","To assign a new IP address to the client involved in the reconstructed conversation flow"], correct:2, explanation:"Following a TCP stream reassembles payload so the conversation can be read. It does not recolor packets, delete them, or reassign IP addresses to the involved hosts." },
  { id:70840, domain:5, level:1, question:"What is the shared responsibility model most concerned with clarifying in IaaS?", options:["Which party is responsible for painting and maintaining the exterior of the datacenter","The exact monthly discount applied to customers who commit to long-term reserved instances in this context","The color scheme the provider uses on its web-based management console dashboards","That the provider secures the underlying infrastructure while the customer secures the guest OS and data"], correct:3, explanation:"In IaaS the provider secures infrastructure and the customer secures the guest OS and data. It is not about building maintenance, pricing discounts, or console color schemes." },
  { id:70841, domain:5, level:3, question:"An analyst must distinguish a legitimate administrator's remote session from an attacker using the same tool. Which evidence combination is most useful?", options:["Source IP reputation, session timing, authentication context, and correlation with change tickets","The tool's official product logo displayed in the vendor's public marketing brochure only in this context","The total number of times the tool has ever been downloaded across the entire internet","The tool's default window size when it first launches on a freshly installed workstation"], correct:0, explanation:"Source reputation, timing, auth context, and change-ticket correlation separate legitimate from malicious use. A logo, global download counts, and default window size are irrelevant to attribution." },
  { id:70842, domain:5, level:2, question:"Which network log is most useful for identifying the internal host behind a NAT that contacted a malicious external IP?", options:["The external website's public privacy policy describing how it handles visitor information in this context","The NAT device's translation log or connection table mapping internal to external endpoints","The internal host's word processor recent-documents list showing recently opened files","The building's HVAC controller log recording temperature setpoints throughout the day"], correct:1, explanation:"The NAT translation log maps internal hosts to external connections, enabling attribution. A privacy policy, a recent-documents list, and HVAC logs cannot identify the host behind NAT." },
  { id:70843, domain:5, level:2, question:"Which observation would most likely indicate ARP cache poisoning was used to enable a man-in-the-middle attack?", options:["A steady set of ARP entries that remain unchanged and match documented static assignments","A DHCP client renewing its lease with the authorized server at the expected halfway point","Two IP addresses on the LAN suddenly resolving to the attacker's single MAC address","An internal host synchronizing its clock with the internal NTP server at regular intervals"], correct:2, explanation:"Multiple IPs resolving to one attacker MAC indicates ARP poisoning for MITM. Stable static entries, normal DHCP renewals, and NTP sync are legitimate, unremarkable behaviors." },
  { id:70844, domain:5, level:1, question:"What information does the sc-status field record in an IIS web server log?", options:["The client's IP address that originated the request to the web server during the session","The full query string parameters the client appended to the requested resource path","The user-agent string identifying the browser or tool the client used for the request","The HTTP status code the server returned to the client indicating the request outcome"], correct:3, explanation:"In IIS logs, sc-status is the HTTP response status code. The client IP is c-ip, the query string is cs-uri-query, and the browser string is cs(User-Agent), not sc-status." },
  { id:70845, domain:5, level:3, question:"An investigator finds outbound TLS traffic whose JA3 fingerprint matches a known malware family. What is the strongest defensible conclusion?", options:["The client's TLS handshake resembles known malware tooling, warranting deeper host investigation","The exact plaintext commands exchanged over the session can be fully decoded from JA3 alone","The user's password was definitely stolen and transmitted, as JA3 always reveals credentials","No conclusion is possible because encrypted traffic can never contribute to any investigation in this context"], correct:0, explanation:"A matching JA3 fingerprint indicates malware-like client tooling and justifies deeper investigation. JA3 does not decode payload, reveal passwords, and encrypted traffic still has forensic value." },
  { id:70846, domain:5, level:2, question:"Which of the following describes the correct handling of cloud log exports as evidence?", options:["Exported logs need no documentation because the cloud provider vouches for their accuracy alone","Exported logs should be hashed, documented with export time and source, and preserved unaltered","Exported logs should be edited to remove entries the investigator considers irrelevant to the case","Exported logs must be deleted from the cloud immediately after export to prevent duplication"], correct:1, explanation:"Cloud log exports should be hashed, documented, and preserved unaltered for integrity. Provider vouching is not sufficient, editing destroys integrity, and deleting the source can harm the case." },
  { id:70847, domain:5, level:2, question:"Which pattern in firewall logs would most likely indicate command-and-control beaconing rather than normal browsing?", options:["Bursts of varied requests to many different popular websites during active user working hours","A large one-time download from a well-known software vendor's official distribution server","Regular small outbound connections to one uncommon external IP at consistent time intervals","Inbound connections from many customers to the organization's public-facing web application"], correct:2, explanation:"Regular small outbound connections to one uncommon IP at fixed intervals suggest beaconing. Varied browsing, a one-time vendor download, and inbound customer traffic are normal patterns." },
  { id:70848, domain:5, level:1, question:"What does the acronym C2 (or C&C) stand for in the context of network intrusions?", options:["Capture and compress, a technique for reducing the storage size of packet capture files","Connect and configure, the process of setting up a new switch on the corporate network","Certificate and credential, the pair of items required to establish a secure TLS session in this context","Command and control, the infrastructure attackers use to direct compromised systems remotely"], correct:3, explanation:"C2 means command and control, the infrastructure directing compromised hosts. The other expansions are invented and do not describe attacker control infrastructure." },
  { id:70849, domain:5, level:3, question:"An analyst investigating a container escape wants to determine what the attacker did on the host. Which evidence is most valuable?", options:["Host-level audit logs, process accounting, and filesystem changes on the underlying node","The container registry's list of image tags available for pulling during normal deployments","The container's welcome banner text displayed when a shell session first attaches to it","The Kubernetes dashboard theme setting selected by the cluster administrator for viewing"], correct:0, explanation:"Host audit logs, process accounting, and filesystem changes reveal post-escape host activity. Image tag lists, welcome banners, and dashboard themes do not show what the attacker did on the host." },
  { id:70850, domain:5, level:2, question:"Which detail most reliably distinguishes a legitimate large file transfer from suspicious bulk exfiltration in flow data?", options:["The transfer's absolute byte count alone, since any transfer over one gigabyte is malicious in this context","The destination, timing, user role, and whether the flow aligns with expected business processes","The color the flow appears as in the analysis tool's default visualization dashboard view","The alphabetical order of the hostnames involved in the source and destination of the flow"], correct:1, explanation:"Destination, timing, user role, and business alignment distinguish legitimate transfers from exfiltration. Byte count alone, tool colors, and hostname alphabetization are not meaningful indicators." },
  { id:70851, domain:5, level:2, question:"Which cloud artifact would best reveal that an attacker launched cryptomining instances in an AWS account?", options:["The S3 bucket naming convention documented in the organization's internal style guide manual in this context","The Route 53 hosted zone's list of DNS records for the company's public marketing website","CloudTrail RunInstances events plus CloudWatch metrics showing sudden sustained high CPU usage","The IAM console's default sorting order for displaying the list of users in the account view"], correct:2, explanation:"RunInstances events plus sustained high CPU metrics reveal unauthorized mining instances. Bucket naming conventions, DNS record lists, and console sort order do not show launched instances." },
  { id:70852, domain:5, level:1, question:"What is the primary purpose of correlating multiple log sources in an investigation?", options:["To reduce the total number of log files that must be retained on the storage server","To automatically encrypt all of the logs so that attackers cannot read their contents","To physically consolidate all servers into a single rack within the primary datacenter in this context","To build a coherent, corroborated picture of events that no single source shows completely"], correct:3, explanation:"Correlation builds a corroborated event picture beyond any single source. It is not about reducing file counts, encrypting logs, or physically consolidating servers." },
  { id:70853, domain:5, level:3, question:"An investigator observes repeated failed then one successful RDP authentication from an external IP, followed by lateral connections. What is the best interpretation?", options:["A likely brute-force compromise of RDP followed by attacker lateral movement inside the network","A benign user who simply forgot their password before eventually remembering it correctly","A routine automated backup process that authenticates using service account credentials nightly","A scheduled vulnerability scan that always produces failed logins as part of its normal testing"], correct:0, explanation:"Failed-then-successful external RDP logins followed by lateral connections indicate brute-force compromise and movement. A forgetful user, a backup job, and a scan do not fit lateral movement from an external IP." },
  { id:70854, domain:5, level:2, question:"Which of the following is a defining feature of a proxy log that aids web attack investigation?", options:["It records the full disk image of each client workstation that made a web request","It records per-request URLs, client identities, timestamps, and response sizes for web traffic","It records the electrical power consumption of the proxy appliance during peak load hours in this context","It records the physical location coordinates of every external server that was contacted"], correct:1, explanation:"Proxy logs record URLs, client identity, time, and response sizes, aiding web investigation. They do not capture disk images, power consumption, or physical server coordinates." },
  { id:70855, domain:5, level:2, question:"Which observation would most strongly suggest an evil twin access point captured a victim's traffic?", options:["A client synchronizing its clock with the internal NTP server after joining the corporate network","A client renewing its DHCP lease with the authorized server at the expected renewal interval","A client associating with an AP whose SSID matches the corporate network but with a foreign BSSID","A client loading cached static images from a trusted CDN with not-modified server responses"], correct:2, explanation:"Associating with a matching SSID but unknown BSSID indicates an evil twin captured the client. NTP sync, normal DHCP renewal, and cached CDN loads are legitimate behaviors." },
  { id:70856, domain:5, level:1, question:"What does a firewall log entry marked as denied typically indicate?", options:["The firewall successfully encrypted the packet before forwarding it to its destination","The firewall assigned a new IP address to the client that initiated the connection","The firewall synchronized its internal clock with an upstream time reference source","The firewall blocked the connection because it violated a configured security rule"], correct:3, explanation:"A denied entry means the firewall blocked traffic that violated a rule. Firewalls do not encrypt packets, assign IP addresses, or perform time sync as part of a deny action." },
  { id:70857, domain:5, level:3, question:"An analyst must prove that a specific insider, not a compromised account, exfiltrated data. Which combination best supports that attribution?", options:["Endpoint session logs, badge access records, and behavior consistent with the insider's presence","The exfiltrated file's icon appearance in the operating system's default file browser view","The external cloud service's uptime percentage during the month the exfiltration took place in this context","The total size of the organization's entire data store measured before and after the event"], correct:0, explanation:"Endpoint sessions, physical badge records, and consistent behavior tie actions to the insider's presence. File icons, cloud uptime, and total store size do not distinguish an insider from a stolen account." },
  { id:70858, domain:5, level:2, question:"Which of the following best describes the forensic value of web server referer log data?", options:["It shows the physical distance in miles between the client and the web server hardware in this context","It shows the page a user came from, helping reconstruct navigation and attack entry paths","It shows the exact encryption key used to protect the TLS session for that request","It shows the amount of RAM installed in the client machine that made the web request"], correct:1, explanation:"The referer shows the originating page, aiding navigation and entry-path reconstruction. It does not reveal physical distance, TLS keys, or client RAM amounts." },
  { id:70859, domain:5, level:2, question:"Which cloud investigation step is most important when a provider stores data across multiple regions?", options:["Assuming all data is in one region and ignoring the possibility of cross-border storage entirely in this context","Immediately deleting the data in other regions to consolidate everything into a single location","Identifying the applicable jurisdictions and legal authority before attempting to acquire the data","Publicly announcing the investigation so that all affected regions are notified simultaneously"], correct:2, explanation:"Identifying jurisdictions and legal authority is essential when data spans regions. Assuming one region, deleting regional copies, and public announcements are inappropriate and harmful." },
  { id:70860, domain:5, level:1, question:"What is the main role of a SIEM correlation rule?", options:["To physically wire together the network cables connecting the monitored devices in a rack in this context","To encrypt the log data at rest using a key stored on the collection appliance's disk","To assign IP addresses to the endpoints that forward their logs to the central collector","To automatically define patterns across events that, when matched, generate a security alert"], correct:3, explanation:"A correlation rule defines cross-event patterns that trigger alerts. It does not wire cables, encrypt data at rest, or assign IP addresses to log sources." },
  { id:70861, domain:5, level:3, question:"An investigator finds that a captured session used HTTP over a nonstandard high port with obfuscated content. What is the best next step?", options:["Analyze the payload structure, correlate with threat intel, and check endpoints for related artifacts","Conclude immediately that the traffic is benign because it does not use the standard web port in this context","Delete the capture since traffic on nonstandard ports is never relevant to any investigation","Assume it is a printer since printers commonly communicate over high nonstandard port numbers"], correct:0, explanation:"Analyzing payload structure, correlating threat intel, and checking endpoints is the sound next step. Assuming benign, deleting the capture, or guessing a printer are unjustified shortcuts." },
  { id:70862, domain:5, level:2, question:"Which detail best helps confirm a captured DNS response was spoofed during a cache poisoning attack?", options:["The response contained a standard TTL value within the normal range configured for the zone","The response arrived from an unexpected source or before the legitimate server could reply","The response resolved a common website to its correct and expected public IP address","The response was logged during business hours when DNS traffic volumes are typically higher"], correct:1, explanation:"A response from an unexpected source or arriving before the real server suggests spoofing. A normal TTL, a correct resolution, and business-hours timing are not signs of poisoning." },
  { id:70863, domain:5, level:2, question:"Which statement about capturing traffic in a switched network is accurate?", options:["Every switch port automatically receives a copy of all traffic on the entire network by default","Switches broadcast all unicast frames to every port, so mirroring is completely unnecessary","A SPAN or mirror port must be configured to send copies of traffic to the capture interface","Capturing on a switch always includes decrypted contents of every encrypted session present"], correct:2, explanation:"A SPAN/mirror port is needed to feed a capture interface in a switched network. Ports do not get all traffic by default, switches do not broadcast unicast, and captures do not decrypt sessions." },
  { id:70864, domain:5, level:1, question:"What does the term exfiltration mean in a network forensics context?", options:["The routine internal backup of files from workstations to a central file server nightly","The process of assigning IP addresses to new devices joining the corporate network","The synchronization of system clocks across servers using a shared time reference","The unauthorized transfer of data out of an organization to an external destination"], correct:3, explanation:"Exfiltration is unauthorized data transfer out of an organization. It is not routine backup, IP assignment, or clock synchronization, which are ordinary operations." },
  { id:70865, domain:5, level:3, question:"An analyst reviewing CloudTrail sees API calls from an unusual region and an unfamiliar user agent. What is the most reasonable interpretation?", options:["Possible credential compromise, since anomalous region and user agent warrant deeper review","The calls are certainly legitimate because CloudTrail only ever records authorized activity","The calls prove the account is fully secure since anomalies indicate the defenses are working","The unusual region is irrelevant because cloud API calls are location-independent by design"], correct:0, explanation:"Anomalous region and user agent suggest possible credential compromise needing review. CloudTrail records all API calls not just authorized ones, anomalies are not proof of security, and region is meaningful." },
  { id:70866, domain:5, level:2, question:"Which of the following is the best reason to capture both directions of a TCP conversation?", options:["To halve the size of the resulting capture file by discarding one side of the exchange","To reconstruct the full request and response so the complete interaction can be analyzed","To ensure the capture automatically decrypts any TLS applied to the conversation content","To assign a unique IP address to each direction of the traffic for easier identification"], correct:1, explanation:"Capturing both directions reconstructs the complete request/response interaction. It does not shrink the file, auto-decrypt TLS, or assign separate IPs per direction." },
  { id:70867, domain:5, level:2, question:"Which observation in Apache logs most strongly suggests a local file inclusion attack attempt?", options:["A request for the site's homepage returning a normal successful status to an ordinary visitor","A conditional request for a cached script returning a not-modified response to a repeat client","A parameter value referencing a system file path such as etc/passwd via traversal sequences","A standard search query submitted through the site's normal search form by a logged-in user"], correct:2, explanation:"A parameter referencing a system path via traversal indicates a local file inclusion attempt. A normal homepage load, a cached-script check, and a routine search are benign requests." },
  { id:70868, domain:5, level:1, question:"What is the primary purpose of a honeypot in network forensics?", options:["To serve production web content to legitimate customers during peak traffic periods","To assign IP addresses to internal clients as they join the corporate network segment","To synchronize the clocks of all servers against a single authoritative time source","To attract and observe attackers so their techniques and tools can be studied safely"], correct:3, explanation:"A honeypot lures attackers so their behavior can be studied in a controlled way. It does not serve production content, assign addresses, or synchronize clocks." },
  { id:70869, domain:5, level:3, question:"An investigator must show that a firewall rule was modified to permit attacker traffic at a precise time. Which evidence is most direct?", options:["The firewall configuration change log entry recording the rule edit, the account, and the timestamp","The firewall's boot-time splash screen image displayed on its local console at power-on","The firewall vendor's published release notes describing features added in the latest firmware in this context","The average temperature of the rack where the firewall appliance was physically installed"], correct:0, explanation:"The config change log entry with the rule edit, account, and timestamp is the most direct evidence. A splash screen, vendor release notes, and rack temperature prove nothing about the rule change." },
  { id:70870, domain:5, level:2, question:"Which characteristic of cloud snapshot acquisition supports forensic soundness?", options:["Modifying the snapshot in place to remove data the investigator believes is not relevant in this context","Documenting the snapshot creation, computing hashes, and analyzing a copy rather than the original","Sharing the only snapshot copy with many analysts who each edit it during their reviews","Deleting the source volume immediately after the snapshot so no duplicate data remains"], correct:1, explanation:"Documenting creation, hashing, and analyzing a copy preserves soundness. Editing the snapshot, sharing an editable sole copy, and deleting the source all undermine evidential integrity." },
  { id:70871, domain:5, level:2, question:"Which of the following best explains why encrypted traffic still holds forensic value even without decryption?", options:["The full plaintext payload is always recoverable from any encrypted session given enough time","Encrypted traffic can be decrypted instantly using the capture tool's built-in default settings","Metadata such as endpoints, timing, volume, certificates, and fingerprints reveals meaningful patterns","Encryption removes all identifying information, leaving nothing whatsoever for an analyst to use in this context"], correct:2, explanation:"Endpoints, timing, volume, certificates, and fingerprints reveal patterns without decryption. Plaintext is not freely recoverable, tools do not decrypt by default, and metadata remains available." },
  { id:70872, domain:5, level:1, question:"What is a PCAP replay used for in a forensic or testing context?", options:["To permanently delete the original capture file after the analysis has been completed in this context","To assign fresh IP addresses to every host referenced within the captured traffic","To automatically encrypt the capture file so its contents cannot be read by others","To retransmit previously captured packets to reproduce or study network behavior offline"], correct:3, explanation:"PCAP replay retransmits captured packets to reproduce behavior for study. It does not delete originals, reassign IP addresses, or encrypt the capture file." },
  { id:70873, domain:5, level:3, question:"An analyst finds that a compromised web server made outbound connections only to internal database and file servers, not the internet. What does this best suggest?", options:["The attacker likely pivoted internally to reach sensitive data stores after the initial foothold","The attacker was interested only in the public homepage and made no further internal moves","The outbound connections prove the web server was never actually compromised at any point","The internal-only traffic confirms the incident was a false alarm requiring no investigation in this context"], correct:0, explanation:"Outbound connections to internal data stores suggest internal pivoting toward sensitive data. It does not indicate mere homepage interest, disprove compromise, or confirm a false alarm." },
  { id:70874, domain:5, level:2, question:"Which detail in a captured wireless frame helps identify which access point a client was communicating with?", options:["The frame's transmit power level setting configured on the client's wireless radio adapter","The BSSID field, which identifies the MAC address of the access point serving the client","The frame's sequence number, which increments with each frame the client transmits over time","The frame's preamble length, which affects the timing of the physical-layer transmission"], correct:1, explanation:"The BSSID identifies the serving access point's MAC address. Transmit power, sequence numbers, and preamble length do not identify which AP the client used." },
  { id:70875, domain:5, level:2, question:"Which practice best preserves the integrity of exported firewall logs used as evidence?", options:["Opening the logs in an editor and reformatting them to make the entries easier to read","Discarding entries that do not appear immediately relevant to reduce the file's overall size","Hashing the exported file and documenting its source, export time, and handling steps","Storing the only copy on a shared drive where multiple analysts can freely modify it"], correct:2, explanation:"Hashing and documenting source, time, and handling preserves log integrity. Reformatting, discarding entries, and using an editable shared sole copy all compromise integrity." },
  { id:70876, domain:5, level:1, question:"What does an access control list (ACL) on a router primarily do?", options:["It encrypts all traffic passing through the router using a negotiated symmetric key","It assigns dynamic IP addresses to hosts as they connect to the local network segment","It synchronizes the router's clock with an authoritative upstream time reference source","It permits or denies packets based on criteria such as source, destination, and port"], correct:3, explanation:"A router ACL permits or denies packets by criteria like address and port. It does not encrypt traffic, assign addresses, or synchronize time as its primary function." },
  { id:70877, domain:5, level:3, question:"An investigator needs to determine whether a spike in DNS queries indicates tunneling or a legitimate application. Which analysis is most decisive?", options:["Examining query name entropy, record types, volume to one server, and correlating with known apps","Counting only the total number of queries, since any high count always means tunneling occurred in this context","Checking the color the DNS traffic is displayed as in the analysis tool's default view settings","Assuming legitimacy because DNS is a core protocol that is never abused by any attacker tooling"], correct:0, explanation:"Query entropy, record types, volume to one server, and app correlation decisively identify tunneling. Raw counts alone, display colors, and blanket assumptions of legitimacy are inadequate." },
  { id:70878, domain:5, level:2, question:"Which of the following is the most accurate description of NetFlow's five-tuple?", options:["The full packet payload, its checksum, timestamp, capture interface, and frame length value","Source IP, destination IP, source port, destination port, and the transport protocol used","The username, password, session token, cookie, and browser string of the connecting client","The physical cable type, connector, switch port, VLAN tag, and spanning-tree state involved"], correct:1, explanation:"The five-tuple is source/destination IP, source/destination port, and protocol. Payload data, credentials, and physical cabling details are not part of the NetFlow five-tuple." },
  { id:70879, domain:5, level:2, question:"Which observation in cloud logs would most likely indicate an attacker attempting privilege escalation?", options:["A user reading a public documentation object stored in a bucket during normal working hours","A scheduled function executing on its normal cron trigger and completing without any errors","API calls attaching elevated IAM policies or roles to an account shortly after a suspicious login","A load balancer distributing inbound requests evenly across a healthy pool of backend servers in this context"], correct:2, explanation:"Attaching elevated policies after a suspicious login indicates privilege escalation. Reading public docs, normal scheduled functions, and load balancing are ordinary, benign activities." },
  { id:70880, domain:5, level:1, question:"What is the purpose of a capture filter versus a display filter in Wireshark?", options:["A capture filter encrypts the traffic, while a display filter decrypts it during the analysis in this context","A capture filter assigns IP addresses, while a display filter assigns port numbers to packets","A capture filter deletes packets permanently, while a display filter restores them on demand","A capture filter limits what is recorded, while a display filter limits what is shown afterward"], correct:3, explanation:"Capture filters limit recording; display filters limit what is shown from recorded data. Neither encrypts, assigns addresses, nor permanently deletes and restores packets." },
  { id:70881, domain:5, level:3, question:"An analyst must show that an attacker's outbound connection succeeded and transferred data, not just attempted. Which evidence is strongest?", options:["Flow or capture data showing a completed session with substantial bytes transferred outbound","A firewall log entry showing only that a connection was attempted from the internal host","A single IDS signature alert with no accompanying packet context or session information at all","The internal host's uptime, which shows it was powered on during the incident time window"], correct:0, explanation:"Completed session flow or capture with substantial bytes proves data transfer, not just an attempt. An attempt-only log, a context-free alert, and uptime do not demonstrate a successful transfer." },
  { id:70882, domain:5, level:2, question:"Which of the following best describes the difference between IaaS and SaaS from an evidence-access standpoint?", options:["In SaaS the customer can image the underlying servers, while in IaaS they cannot at all","In IaaS the customer controls the VM and can snapshot it, while in SaaS they rely on provider logs","In both models the customer always receives full physical access to the provider's datacenter","In neither model is any log or evidence ever available to the customer under any circumstances in this context"], correct:1, explanation:"In IaaS customers snapshot their VMs; in SaaS they depend on provider-exposed logs. The reverse claim is wrong, physical access is never granted, and logs are generally available." },
  { id:70883, domain:5, level:2, question:"Which detail in a proxy log helps confirm the amount of data transferred during a suspicious session?", options:["The user-agent string recording the browser and operating system the client reported using","The requested URL path recording which resource on the destination server was requested","The response size or bytes field recording how many bytes were returned for the request","The HTTP method field recording whether the request used GET, POST, or another verb"], correct:2, explanation:"The bytes/response-size field records data volume for the session. The user-agent, URL path, and HTTP method describe the client and request but not the transferred data amount." },
  { id:70884, domain:5, level:1, question:"What does a deauthentication attack against a wireless network accomplish?", options:["It permanently steals the pre-shared key stored in the access point's flash memory chip in this context","It assigns new IP addresses to every client currently associated with the access point","It encrypts all wireless traffic so that only the attacker can read the client's data","It forces connected clients to disconnect from the access point, disrupting their sessions"], correct:3, explanation:"A deauth attack forces clients off the AP, disrupting sessions and often forcing reconnection. It does not steal the PSK from flash, assign IP addresses, or encrypt client traffic." },
  { id:70885, domain:5, level:3, question:"An investigator finds a cloud function was modified to send data to an external endpoint. Which log best establishes who made the change and when?", options:["The cloud provider's audit log recording the update API call, the caller identity, and timestamp","The function's runtime memory dump captured while it was actively processing a request","The external endpoint's public terms of service describing acceptable use of its service in this context","The function's average execution duration metric measured across the past thirty days"], correct:0, explanation:"The audit log of the update API call with caller identity and timestamp establishes who and when. A memory dump, external terms of service, and duration metrics do not identify the change author." },
  { id:70886, domain:5, level:2, question:"Which of the following best describes why SIEM correlation reduces investigation time?", options:["It physically consolidates all the servers into a single rack for easier cabling and cooling in this context","It automatically links related events across sources, surfacing likely incidents for the analyst","It encrypts every log so that analysts spend less time worrying about unauthorized access","It deletes low-severity events so that the analyst never has to review any of them again"], correct:1, explanation:"SIEM correlation links related events across sources to surface incidents faster. It does not consolidate hardware, and encrypting or deleting events is not what saves investigation time." },
  { id:70887, domain:5, level:2, question:"Which observation would most strongly indicate a proxy was bypassed by a host communicating directly to the internet?", options:["Proxy logs showing the host making its normal browsing requests through the configured proxy","DNS logs showing the host resolving internal hostnames for corporate application servers","Firewall logs showing outbound connections from a host that never appear in the proxy access logs","DHCP logs showing the host renewing its lease with the authorized server at the usual interval in this context"], correct:2, explanation:"Outbound connections in firewall logs absent from proxy logs indicate proxy bypass. Normal proxied browsing, internal DNS lookups, and DHCP renewals show expected, compliant behavior." },
  { id:70888, domain:5, level:1, question:"What is the main forensic benefit of capturing full packet data over only flow records?", options:["Full packet data is always smaller than flow records, saving storage on the analysis server in this context","Full packet data automatically decrypts encrypted sessions without needing any keys at all","Full packet data assigns permanent IP addresses to every host observed in the capture file","Full packet data preserves payload contents, enabling reconstruction of what was communicated"], correct:3, explanation:"Full packet data keeps payloads for reconstruction, unlike metadata-only flows. It is larger not smaller, does not auto-decrypt, and does not assign IP addresses." },
  { id:70889, domain:5, level:3, question:"An analyst investigating a hybrid environment must reconcile timestamps from on-prem logs in local time and cloud logs in UTC. What is the correct approach?", options:["Normalize all timestamps to a single reference such as UTC before building the event timeline","Assume both sets of logs already use the same time zone and compare their timestamps directly","Discard the cloud logs entirely because mixing time zones makes correlation impossible to do","Adjust only the cloud timestamps randomly until the events appear to line up with expectations"], correct:0, explanation:"Normalizing all timestamps to one reference like UTC enables accurate correlation. Assuming matching zones, discarding cloud logs, and random adjustments all produce incorrect timelines." },
  { id:70890, domain:5, level:2, question:"Which detail most reliably indicates that captured traffic represents a legitimate TLS session rather than an anomaly?", options:["A self-signed certificate presented for a well-known public banking or shopping website","A valid certificate chain to a trusted CA, expected SNI, and a normal cipher negotiation","A handshake to an IP with no certificate presented and immediate opaque binary data flow","A connection whose destination matches a domain listed on a current threat intelligence feed"], correct:1, explanation:"A trusted CA chain, expected SNI, and normal cipher negotiation indicate a legitimate session. Self-signed certs on major sites, missing certificates, and threat-listed destinations are anomalies." },
  { id:70891, domain:5, level:1, question:"What does the shared responsibility model imply about SaaS security duties?", options:["The customer is fully responsible for securing the underlying servers and operating systems","The provider has no security responsibilities and the customer must secure everything themselves in this context","The provider secures the application and infrastructure while the customer manages access and data use","Neither the provider nor the customer has any responsibility for the security of the application"], correct:2, explanation:"In SaaS the provider secures the app and infrastructure while the customer manages access and data. The customer does not secure the servers, and responsibility is shared, not absent." },
  { id:70892, domain:5, level:3, question:"An analyst observes that logs stopped being forwarded to the SIEM shortly before a suspected breach. What is the most reasonable interpretation?", options:["The gap is irrelevant because SIEM forwarding pauses are a normal daily maintenance routine","The absence of logs conclusively proves that no breach could have occurred during that period","The SIEM itself was clearly the target of the breach because it stopped receiving the logs","An attacker may have disrupted log forwarding to evade detection, warranting closer scrutiny"], correct:3, explanation:"A forwarding gap right before a breach suggests possible anti-forensic tampering to evade detection. It is not routine, does not disprove a breach, and does not itself implicate the SIEM as target." },
  { id:70893, domain:5, level:2, question:"Which characteristic of a captured HTTP POST body would most suggest command-and-control communication rather than a form submission?", options:["An opaque, high-entropy or encoded blob sent repeatedly to an unfamiliar external endpoint","A human-readable set of form field names and values matching the visible fields of a web form","A standard file upload with a recognized content type and an expected multipart boundary marker","A short search term submitted to the site's own search endpoint returning normal results"], correct:0, explanation:"An opaque high-entropy blob sent repeatedly to an unknown endpoint suggests C2. Readable form fields, standard uploads, and search terms are ordinary web form submissions." },
  { id:70894, domain:5, level:2, question:"Which of the following is the best reason to preserve DNS logs during a malware investigation?", options:["DNS logs contain the full decrypted contents of every web page the user ever visited","DNS logs reveal which domains hosts resolved, helping identify C2 and malicious infrastructure","DNS logs record the physical serial numbers of the network cards installed in each host","DNS logs store the complete browser history including page titles for each website visited in this context"], correct:1, explanation:"DNS logs reveal resolved domains, exposing C2 and malicious infrastructure. They do not contain page contents, hardware serials, or full browser history with titles." },
  { id:70895, domain:5, level:1, question:"What is the primary purpose of NetFlow or IPFIX collection in an enterprise?", options:["To encrypt all network traffic between internal hosts and external destination servers in this context","To assign IP addresses to devices dynamically as they connect to the network segments","To record summarized metadata about network conversations for monitoring and investigation","To physically route packets between different subnets across the enterprise backbone"], correct:2, explanation:"NetFlow/IPFIX records conversation metadata for monitoring and investigation. It does not encrypt traffic, assign IP addresses, or physically route packets between subnets." },
  { id:70896, domain:5, level:3, question:"An investigator needs to prove that a specific S3 object was downloaded by an attacker. Which evidence is most direct?", options:["The bucket's overall storage size measured before and after the suspected download event","The object's file type as inferred from its extension in the bucket's object listing view","The provider's marketing material describing the durability guarantees of the storage service in this context","An S3 server access log or CloudTrail data event recording the GetObject request and requester"], correct:3, explanation:"An access log or CloudTrail data event recording GetObject with the requester directly proves the download. Storage size, file extension, and durability marketing do not show who downloaded the object." },
  { id:70897, domain:5, level:2, question:"Which observation would most strongly suggest a DDoS amplification attack using a reflector service?", options:["Large responses from open services like DNS or NTP flooding a spoofed victim's address","A single client completing a normal DNS query and receiving one small expected response","Two internal servers exchanging a steady authenticated session over an encrypted channel","A user browsing several websites sequentially with typical request and response sizes"], correct:0, explanation:"Amplification uses large responses from services like DNS or NTP aimed at a spoofed victim. A normal single query, an internal session, and ordinary browsing are not amplification attacks." },
  { id:70898, domain:5, level:1, question:"What does the term chain of custody ensure for network and cloud evidence?", options:["That the evidence is encrypted with a key known only to the lead investigator on the case","That every person who handled the evidence and when is documented to preserve its integrity","That the evidence is automatically deleted after a fixed retention period regardless of the case","That the evidence is copied to as many analysts as possible so everyone can edit it freely"], correct:1, explanation:"Chain of custody documents who handled evidence and when to preserve integrity. It is not about encrypting with one key, auto-deletion, or freely distributing editable copies." },
  { id:70899, domain:5, level:3, question:"An analyst finds outbound connections to a cloud provider's IP ranges but cannot see the destination service. What is the best investigative approach?", options:["Conclude the traffic is benign since it goes to a reputable cloud provider's address ranges","Delete the capture because traffic to cloud providers is never relevant to any investigation in this context","Use SNI, TLS certificate details, DNS logs, and flow patterns to infer the destination service","Assume the traffic is a software update since all cloud provider traffic consists of updates"], correct:2, explanation:"Using SNI, certificates, DNS logs, and flow patterns helps infer the hidden destination. Assuming benign, deleting the capture, or assuming updates are unjustified investigative shortcuts." },
  { id:70900, domain:5, level:2, question:"Which practice best supports admissibility when collecting evidence from a cloud provider?", options:["Relying only on informal verbal assurances from the provider that the data is accurate","Screenshotting the console once and discarding all underlying log exports afterward entirely in this context","Editing the exported records to highlight the entries the investigator finds most important","Using documented legal process, preserving provider attestations, and recording collection details"], correct:3, explanation:"Documented legal process, provider attestations, and recorded collection details support admissibility. Verbal assurances, discarding exports, and editing records all undermine the evidence's admissibility." },
];
